import { callApi } from "./client";

export function fetchCallCenterData(callback: any, failureCallback?: any) {
  callApi("fetchCallCenterData")
    .then(callback)
    .catch(
      failureCallback ||
        (() => {
          console.log("fetchCallCenterData Failed");
        })
    );
}

export function fetchMachineInformation(machineId: string, callback: any) {
  callApi("queryDBInformationByMachineID", { machineId })
    .then(callback)
    .catch(() => {
      console.log("fetchCallCenterData Failed");
    });
}

export function fetchUserIDMapping(callback: any) {
  callApi("queryUserIDMapping")
    .then(callback)
    .catch(() => {
      console.log("fetchUserIDMapping Failed");
    });
}

export function uploadFileToGoogleDrive(
  caseID: any,
  base64File: any,
  callback: any,
  failureCallback: any
) {
  callApi("uploadFileToGoogleDrive", { timestamp: caseID, base64File })
    .then(callback)
    .catch(failureCallback);
}

export function removeFileByID(fileId: any, callback: any) {
  callApi("removeFileById", { fileId })
    .then(callback)
    .catch(() => {
      console.log("removeFileById Failed");
    });
}

export function updateCaseStatusFromConsole(
  currentCaseDataRowNum: number,
  updateForm: any,
  callback: any
) {
  callApi("updateCaseStatusFromConsole", {
    rowNum: currentCaseDataRowNum,
    updateObject: updateForm,
  })
    .then((returnObj: any) => {
      callback(returnObj);
    })
    .catch(() => {
      console.log("updateCaseStatusFromConsole Failed");
    });
}

export function addOrEditCase(updateObject: any, callback: any) {
  callApi("addOrEditCase", { updateObject })
    .then((returnObj: any) => {
      callback(returnObj);
    })
    .catch(() => {
      console.log("addOrEditCase Failed");
    });
}

export function getCustomerContactAndMachine(
  customerID: string,
  callback: any
) {
  callApi("getCustomerContactAndMachine", { customerID })
    .then(callback)
    .catch(() => {
      console.log("getCustomerContactAndMachine Failed");
    });
}
