
import { computed, defineComponent, onMounted, ref } from "vue";
import { Table } from "ant-design-vue";
import { fetchAllMachineHistory } from "@/api/machine-history";

interface machineIDMapRecord {
  異動記錄: any[];
  維修記錄: any[];
  財產入庫日: string;
  財產名稱: string;
  財產目前客戶代號: string;
  財產目前客戶名稱: string;
  財產編號: string;
}
interface timelineEvent {
  日期: string;
  日期加註: string | null | undefined;
  事件說明: string;
  "事件說明-2"?: string | null | undefined;
  "事件說明-3"?: string | null | undefined;
  簽單類型: string;
  簽單單號?: string | null | undefined;
  簽單位置?: string | null | undefined;
  維修單號: string;
  事件類別: string;
  事件tag: string;
  詳細: any;
}

export default defineComponent({
  components: {
    ATable: Table,
  },
  setup() {
    const sortedMachineActivites = ref<timelineEvent[]>([]);
    const searchBoxValue = ref("義大");
    const gsQuerying = ref(true);
    const machineIDMaps = ref<machineIDMapRecord[]>([]);
    const customerMaps = ref<Record<string, string>>({});
    const columns = [
      {
        title: "序號",
        dataIndex: "財產編號",
        key: "財產編號",
        width: 120,
        sorter: (a: machineIDMapRecord, b: machineIDMapRecord) =>
          a["財產編號"] > b["財產編號"] ? 1 : -1,
      },
      {
        title: "品名",
        dataIndex: "財產名稱",
        key: "財產名稱",
        width: 180,
        sorter: (a: machineIDMapRecord, b: machineIDMapRecord) =>
          a["財產名稱"] > b["財產名稱"] ? 1 : -1,
      },
      {
        title: "客戶代號",
        dataIndex: "財產目前客戶代號",
        key: "財產目前客戶代號",
        width: 120,
        sorter: (a: machineIDMapRecord, b: machineIDMapRecord) =>
          a["財產目前客戶代號"] > b["財產目前客戶代號"] ? 1 : -1,
      },
      {
        title: "財產位置",
        dataIndex: "財產目前客戶名稱",
        key: "財產目前客戶名稱",
        sorter: (a: machineIDMapRecord, b: machineIDMapRecord) =>
          a["財產目前客戶名稱"] > b["財產目前客戶名稱"] ? 1 : -1,
      },
      {
        title: "檢視",
        key: "檢視",
        width: 100,
      },
    ];
    const timelineTableColumns = [
      {
        title: "品名",
        dataIndex: "品名",
        key: "品名",
      },
      {
        title: "數量",
        dataIndex: "數量",
        key: "數量",
      },
      {
        title: "金額",
        dataIndex: "金額",
        key: "金額",
      },
    ];

    onMounted(() => {
      fetchAllMachineHistory((data: any) => {
        gsQuerying.value = false;
        machineIDMaps.value = data["財產記錄"];
        customerMaps.value = data["客編對應"];
      });
    });

    // 處理手寫工單、電子工單的簽單號及資訊
    const retrieveSignSheetObj = (note: string): any => {
      let signSheetNum = "";
      let position = "";
      let signSheetType = "";
      if (note.indexOf("自動填單") >= 0) {
        // 電子工單
        let regex = /<簽單編號：(.*)>/;
        let match = regex.exec(note);
        if (match) {
          signSheetNum = match[1];
        }
        signSheetType = "電子";
      } else {
        // 手寫工單
        // retreive AA010242 in "AA010242 上庭" or "AA010242    中文" use regex
        let regex = /([A-Za-z]{2}[0-9]{6})\s*(\p{Script=Han}+)/u;
        let match = regex.exec(note);
        if (match) {
          signSheetNum = match[1];
          position = match[2];
        }
        signSheetType = "手寫";
      }
      return {
        簽單類型: signSheetType,
        簽單單號: signSheetNum,
        簽單位置: position,
      };
    };

    // 處理搜尋
    const showMachineIDMaps = computed(() => {
      let lowercasedSearchBoxValue = searchBoxValue.value.toLowerCase();
      return machineIDMaps.value.filter(
        (data) =>
          !searchBoxValue.value ||
          data["財產編號"].toLowerCase().includes(lowercasedSearchBoxValue) ||
          data["財產名稱"].toLowerCase().includes(lowercasedSearchBoxValue) ||
          data["財產目前客戶代號"]
            .toLowerCase()
            .includes(lowercasedSearchBoxValue) ||
          data["財產目前客戶名稱"]
            .toLowerCase()
            .includes(lowercasedSearchBoxValue)
      );
    });
    const createTimeLine = (machineRecord: machineIDMapRecord) => {
      sortedMachineActivites.value = [];
      sortedMachineActivites.value.push({
        日期: machineRecord["財產入庫日"],
        日期加註: "",
        事件說明: "財產入庫",
        事件類別: "特殊",
        事件tag: "入庫",
        詳細: null,
        簽單類型: "手寫",
        維修單號: "",
      });

      for (let i = 0; i < machineRecord["異動記錄"].length; i++) {
        sortedMachineActivites.value.push({
          日期: machineRecord["異動記錄"][i]["異動日期"],
          日期加註: null,
          事件說明:
            machineRecord["異動記錄"][i]["異動單別"] == "收回"
              ? "收回公司"
              : machineRecord["異動記錄"][i]["異動至"],
          事件類別: "特殊",
          事件tag: machineRecord["異動記錄"][i]["異動單別"],
          "事件說明-2": null,
          詳細: machineRecord["異動記錄"][i],
          簽單類型: "手寫",
          維修單號: "",
        });
      }

      for (let i = 0; i < machineRecord["維修記錄"].length; i++) {
        let signSheetObj = retrieveSignSheetObj(
          machineRecord["維修記錄"][i]["備註"]
        );

        sortedMachineActivites.value.push({
          日期: machineRecord["維修記錄"][i]["維修日期"],
          日期加註:
            customerMaps.value[machineRecord["維修記錄"][i]["客戶編號"]],
          事件說明: machineRecord["維修記錄"][i]["記錄杯數"]
            ? machineRecord["維修記錄"][i]["記錄杯數"] + "杯"
            : "",
          事件類別:
            machineRecord["維修記錄"][i]["維修單別"] == "保養"
              ? "一般"
              : "特殊",
          事件tag:
            machineRecord["維修記錄"][i]["維修單別"] == "其它"
              ? "其它維修"
              : machineRecord["維修記錄"][i]["維修單別"],
          "事件說明-2":
            machineRecord["維修記錄"][i]["總金額"] &&
            machineRecord["維修記錄"][i]["總金額"] != "0"
              ? "收費 $ " + machineRecord["維修記錄"][i]["總金額"]
              : null,
          詳細: machineRecord["維修記錄"][i],
          簽單類型: signSheetObj["簽單類型"],
          簽單單號: signSheetObj["簽單單號"],
          簽單位置: signSheetObj["簽單位置"],
          維修單號: machineRecord["維修記錄"][i]["維修單索引"],
        });
      }

      sortedMachineActivites.value.sort((a, b) => {
        if (parseInt(b["日期"]) == parseInt(a["日期"])) {
          var bVal = 0;
          var aVal = 0;
          if (a["事件tag"].toString().indexOf("入庫") >= 0) {
            aVal += 10000;
          }
          if (b["事件tag"].toString().indexOf("入庫") >= 0) {
            bVal += 10000;
          }
          if (
            a["事件tag"].toString().indexOf("移轉") >= 0 ||
            a["事件tag"].toString().indexOf("外送") >= 0 ||
            a["事件tag"].toString().indexOf("收回") >= 0
          ) {
            aVal += 1000;
          }
          if (
            b["事件tag"].toString().indexOf("移轉") >= 0 ||
            b["事件tag"].toString().indexOf("外送") >= 0 ||
            b["事件tag"].toString().indexOf("收回") >= 0
          ) {
            bVal += 1000;
          }
          return aVal - bVal;
        } else {
          return parseInt(b["日期"]) - parseInt(a["日期"]);
        }
      });
    };

    const getColorByEventTag = (tag: string): string => {
      switch (tag) {
        case "入庫":
          return "orange";
        case "出庫":
          return "orange";
        case "保養":
          return "green";
        case "維修":
          return "red";
        case "其它維修":
          return "red";
        case "外送":
          return "cyan";
        case "收回":
          return "cyan";
        default:
          return "pink";
      }
    };

    return {
      showMachineIDMaps,
      sortedMachineActivites,
      searchBoxValue,
      gsQuerying,
      createTimeLine,
      columns,
      timelineTableColumns,
      getColorByEventTag,
    };
  },
});
