
import { defineComponent, reactive, watchEffect, ref, onMounted } from "vue";
import locale from "ant-design-vue/es/date-picker/locale/zh_TW";
import { PlusOutlined, DeleteOutlined } from "@ant-design/icons-vue";
import {
  fetchInnerCostData,
  updateTransferSettingData,
} from "@/api/inner-cost-data";
import dayjs from "dayjs";
import "dayjs/locale/zh-tw";

const signSheetColumns = [
  { title: "日期／單號", key: "日期", width: 120 },
  { title: "客戶", key: "客戶", width: 150 },
  { title: "成本", key: "成本", width: 150, className: "v-align-top-col" },
  {
    title: "成本轉移",
    key: "成本轉移",
    width: 180,
    className: "v-align-top-col",
  },
  { title: "收入", key: "收入", width: 150, className: "v-align-top-col" },
  {
    title: "收入轉移",
    key: "收入轉移",
    width: 180,
    className: "v-align-top-col",
  },
  { title: "備註", key: "備註", width: 100 },
  { title: "修改", key: "修改" },
];

// 原廠索賠、業務、工程、贈送
const balanceTransferOption = {
  成本: [
    { value: "業務部", label: "業務部" },
    { value: "工程部", label: "工程部" },
    { value: "商品部", label: "商品部" },
    { value: "行銷部", label: "行銷部" },
    { value: "原廠索賠", label: "原廠索賠" },
  ],
  收入: [
    { value: "業務", label: "業務" },
    { value: "工程", label: "工程" },
  ],
};

const repairSheetColumns = [
  { title: "機號", dataIndex: "machineID", key: "machineID" },
  { title: "規格", dataIndex: "machineName", key: "machineName" },
  { title: "收費", key: "收費" },
  { title: "備註", key: "備註", width: 500 },
];

const partsColumns = [
  { title: "零件編號", dataIndex: "partsID", key: "零件編號" },
  { title: "規格", dataIndex: "partsName", key: "零件名稱" },
  { title: "數量", dataIndex: "partsCount", key: "零件數量" },
  { title: "收費", dataIndex: "partsPrice", key: "零件單價" },
];

const signSheetTypeFilterOption = [
  { value: "固資", label: "固資" },
  { value: "存貨", label: "存貨" },
  { value: "自購", label: "自購" },
  { value: "其他", label: "其他" },
];

const signSheetAccountFilterOption = [
  { value: "業務部", label: "業務部" },
  { value: "工程部", label: "工程部" },
  { value: "商品部", label: "商品部" },
  { value: "行銷部", label: "行銷部" },
  { value: "原廠索賠", label: "原廠索賠" },
  { value: "零成本", label: "零成本" },
];

export default defineComponent({
  name: "ProfitCenterCostViewer",
  components: {
    PlusOutlined,
    DeleteOutlined,
  },
  props: {},
  setup() {
    dayjs.locale("zh-tw");

    const isLoading: any = ref(false);
    const dbData: any = reactive({
      rawData: null,
      displayData: [],
      filteredDisplayData: [],
      oneTripLaborCostInput: 600,
      discountForCostInput: 70,
    });
    const displayData: any = reactive({
      invoice: {
        簽單總數: 0,
        成本轉移: {},
        收入轉移: {},
        列數: 0,
      },
    });

    onMounted(() => {
      reloadData();
    });
    const reloadData = () => {
      isLoading.value = true;
      fetchInnerCostData((data: any): void => {
        // console.log(data);
        let preDbRawData = data; // 避免觸發 watchEffect
        let signSheetMap: any = {};

        let signSheetData = data["signSheetData"];
        let repairSheetData = data["repairSheetData"];
        for (let i = 1; i < signSheetData.length; i++) {
          if (signSheetData[i][3] != "已拋轉") continue;
          let cuSignSheetData = JSON.parse(signSheetData[i][2]);
          signSheetMap[cuSignSheetData.timestamp] = cuSignSheetData;
          signSheetMap[cuSignSheetData.timestamp]["repairRows"] = [];
          for (let j = 0; j < cuSignSheetData.signRows.length; j++) {
            let cuRepairSheetData = JSON.parse(
              repairSheetData[cuSignSheetData.signRows[j] - 1][2]
            );
            signSheetMap[cuSignSheetData.timestamp].repairRows.push(
              cuRepairSheetData
            );
          }
        }
        preDbRawData["signSheetMap"] = signSheetMap;
        dbData.rawData = JSON.parse(JSON.stringify(preDbRawData));
      });
    };

    watchEffect(() => {
      if (!dbData.rawData) return;
      isLoading.value = true;
      dbData.displayData = [];
      // dbData.rawData["signSheetMap"] 是個 map
      // 這邊透過轉換 dbData.rawData["signSheetMap"] 來產生 dbData.displayData
      Object.keys(dbData.rawData["signSheetMap"])
        .sort((a, b) => {
          // \d{4}-2024-01-05-163802
          let dateA: any = dayjs(a.slice(5), "YYYY-MM-DD-HHmmss");
          let dateB: any = dayjs(b.slice(5), "YYYY-MM-DD-HHmmss");
          return dateB - dateA;
        })
        .forEach((key) => {
          // 每一張簽單
          const row = dbData.rawData["signSheetMap"][key];
          let totalCoffeeMachineCount = row.repairRows.filter(
            (repairRow: any) =>
              repairRow.machineName
                ? repairRow.machineName.includes("咖啡機")
                : false
          ).length;
          let totalLaborCost =
            dbData.oneTripLaborCostInput * totalCoffeeMachineCount;
          let totalPartsCost = 0;
          let totalLaborIncome = 0;
          let totalPartsIncome = 0;
          let machineTypeList: any = {}; // 這張簽單中的機種類型
          row.repairRows.forEach((repairRow: any) => {
            // 每一張簽單中的每一張維修單

            // 確認是否有固資維修
            let machineIdInDatabase =
              dbData.rawData["machineTypeMap"][repairRow.machineID];
            let machineType = machineIdInDatabase
              ? machineIdInDatabase["類型"]
              : "其他";

            machineTypeList[machineType] = true;

            repairRow.parts.forEach((subItem: any) => {
              // 每一張維修單中的每一個零件
              let partsID = subItem.partsID;
              let innerPartsUnitPrice = NaN;
              if (partsID == "93000013") {
                innerPartsUnitPrice = 0;
              } else if (partsID in dbData.rawData["priceMap"]) {
                innerPartsUnitPrice =
                  dbData.rawData.priceMap[partsID]["業務底價"];
              }

              // 計算 Cost
              totalPartsCost += innerPartsUnitPrice * subItem.partsCount;

              // 計算 Income
              if (partsID == "93000013") {
                // 如果零件名稱中含有，工資、車資、油資等等，計入工資收入
                totalLaborIncome += subItem.partsCount * subItem.partsPrice;
              } else {
                totalPartsIncome += subItem.partsCount * subItem.partsPrice;
              }
            }); // end of 每一張維修單中的每一個零件
          }); // end of 每一張簽單中的每一張維修單
          // console.log(row);
          let copyRow = JSON.parse(JSON.stringify(row));
          copyRow.零件成本 = totalPartsCost;
          copyRow.工資成本 = totalLaborCost;
          copyRow.零件收入 = totalPartsIncome;
          copyRow.工資收入 = totalLaborIncome;
          copyRow.機種類型 = Object.keys(machineTypeList);
          copyRow.咖啡機數量 = totalCoffeeMachineCount;

          // 這邊要讀取設定檔，如果有下面的資料，就要自動代入
          let manualTransferSetting = dbData.rawData["settingMap"][key];
          if (manualTransferSetting) {
            // 如果有存好的手動設定，就要代入
            copyRow.成本轉移 = manualTransferSetting["成本轉移"];
            copyRow.收入轉移 = manualTransferSetting["收入轉移"];
            copyRow.備註 = manualTransferSetting["備註"];
            copyRow.手動設定 = true;
          } else {
            // 如果沒有存好的手動設定，就要自動計算
            copyRow.成本轉移 = [];
            copyRow.收入轉移 = [];
            copyRow.備註 = "";
            copyRow.手動設定 = false;

            // 這邊要透過簽單性質自動計算轉移金額
            if (copyRow.機種類型.includes("固資")) {
              if (totalPartsIncome + totalLaborIncome > 0) {
                // 工程有收費，不向業務轉移
                copyRow.成本轉移 = [
                  {
                    單位: "工程部",
                    金額: totalLaborCost + totalPartsCost,
                  },
                ];
                copyRow.收入轉移 = [
                  {
                    單位: "工程部",
                    金額: totalPartsIncome + totalLaborIncome,
                  },
                ];
              } else {
                // 工程沒有收費，向業務轉移
                copyRow.成本轉移 = [
                  {
                    單位: "業務部",
                    金額: totalLaborCost + totalPartsCost,
                  },
                ];
              }
            } else {
              // 其它維修，向工程轉移
              copyRow.成本轉移 = [
                {
                  單位: "工程部",
                  金額: totalLaborCost + totalPartsCost,
                },
              ];
              if (totalPartsIncome + totalLaborIncome > 0) {
                copyRow.收入轉移 = [
                  {
                    單位: "工程部",
                    金額: totalPartsIncome + totalLaborIncome,
                  },
                ];
              }
            }
          }

          dbData.displayData.push(copyRow);
        }); // end of 每一張簽單
      onChangeAnyFilter();
    });

    // Model data
    const transerSettingVisible = ref(false);
    const confirmLoading = ref(false);
    const currentModifyingtranserSetting = ref<any>({});
    const onOpenTranserSetting = (record: any) => {
      currentModifyingtranserSetting.value = {
        簽單號碼: record.timestamp,
        客戶名稱: record.customerName,
        帳面總成本: record.零件成本 + record.工資成本,
        帳面總收入: record.零件收入 + record.工資收入,
        成本轉移: JSON.parse(JSON.stringify(record.成本轉移)),
        收入轉移: JSON.parse(JSON.stringify(record.收入轉移)),
        備註: record.備註,
      };
      transerSettingVisible.value = true;
    };
    const onUpdateCostTransferSetting = () => {
      confirmLoading.value = true;
      console.log(currentModifyingtranserSetting.value);
      // 清掉沒有單位 或 金額為 0 的項目
      currentModifyingtranserSetting.value["成本轉移"] =
        currentModifyingtranserSetting.value["成本轉移"].filter(
          (item: any) => item.單位 && item.金額
        );
      currentModifyingtranserSetting.value["收入轉移"] =
        currentModifyingtranserSetting.value["收入轉移"].filter(
          (item: any) => item.單位 && item.金額
        );
      // prepare data for db
      let caseNumber = currentModifyingtranserSetting.value.簽單號碼;
      let copyTranserSetting = {
        簽單號碼: caseNumber,
        成本轉移: JSON.parse(
          JSON.stringify(currentModifyingtranserSetting.value.成本轉移)
        ),
        收入轉移: JSON.parse(
          JSON.stringify(currentModifyingtranserSetting.value.收入轉移)
        ),
        備註: currentModifyingtranserSetting.value.備註,
      };
      updateTransferSettingData(copyTranserSetting, () => {
        // 這邊應該避免 reload，而是直接更新 dbData.rawData["settingMap"]
        // reloadData();
        delete copyTranserSetting.簽單號碼;
        dbData.rawData["settingMap"][caseNumber] = copyTranserSetting;
        confirmLoading.value = false;
        transerSettingVisible.value = false;
      });
    };
    const currentSettingAddRow = (transerMode: string) => {
      currentModifyingtranserSetting.value[transerMode + "轉移"].push({
        單位: "",
        金額: 0,
      });
    };
    const currentSettingDeleteRow = (transerMode: string, index: number) => {
      currentModifyingtranserSetting.value[transerMode + "轉移"].splice(
        index,
        1
      );
    };

    // Filter
    const rangePickerValue = ref<[dayjs.Dayjs, dayjs.Dayjs]>();
    rangePickerValue.value = [dayjs().startOf("month"), dayjs().endOf("month")];
    const signSheetTypeFilter = ref<string[]>(["固資", "存貨", "自購"]);
    const signSheetAccountFilter = ref<string>();
    const customerSearchValue = ref<string | null>(null);

    const onChangeAnyFilter = () => {
      console.log("onChangeAnyFilter");
      isLoading.value = true;

      if (customerSearchValue.value) {
        customerSearchValue.value = customerSearchValue.value.trim();
      }

      // dbData.rawRepairData = {};
      dbData.filteredDisplayData = [];
      displayData.invoice = {
        簽單總數: 0,
        成本轉移: {},
        收入轉移: {},
        列數: 0,
      };
      dbData.filteredDisplayData = dbData.displayData.filter((row: any) => {
        if (customerSearchValue.value) {
          if (
            !row.customerName.includes(customerSearchValue.value) &&
            !row.customerID.includes(customerSearchValue.value)
          )
            return false;
        }
        if (rangePickerValue.value) {
          let repairDate = row.timestamp.slice(5);
          let dayjsObj = dayjs(repairDate, "YYYY-MM-DD-HHmmss");
          if (rangePickerValue.value[0].startOf("date") > dayjsObj)
            return false;
          if (dayjsObj > rangePickerValue.value[1].endOf("date")) return false;
        }
        // 依機種類型篩選
        if (signSheetTypeFilter.value.length > 0) {
          let machineTypeList = row.機種類型;
          let isMatch = false;
          signSheetTypeFilter.value.forEach((item) => {
            if (machineTypeList.includes(item)) {
              isMatch = true;
            }
          });
          if (!isMatch) return false;
        }
        // 依帳戶篩選
        if (signSheetAccountFilter.value === "零成本") {
          const totalCostTransfer = row.成本轉移.reduce(
            (acc: any, cur: any) => acc + cur.金額,
            0
          );
          if (totalCostTransfer !== 0) return false;
        } else if (signSheetAccountFilter.value) {
          let isMatch = false;
          row.成本轉移.forEach((item: any) => {
            if (item.單位 == signSheetAccountFilter.value && item.金額 > 0) {
              isMatch = true;
            }
          });
          if (!isMatch) return false;
        }
        // 邊計算有列入的簽單統計
        displayData.invoice["簽單總數"] += 1;
        row.成本轉移.forEach((item: any) => {
          if (item.單位 in displayData.invoice["成本轉移"]) {
            displayData.invoice["成本轉移"][item.單位] += item.金額;
          } else {
            displayData.invoice["成本轉移"][item.單位] = item.金額;
          }
        });
        row.收入轉移.forEach((item: any) => {
          if (item.單位 in displayData.invoice["收入轉移"]) {
            displayData.invoice["收入轉移"][item.單位] += item.金額;
          } else {
            displayData.invoice["收入轉移"][item.單位] = item.金額;
          }
        });
        return true;
      });

      // 修改 displayData.invoice 的格式
      displayData.invoice["成本轉移"] = Object.keys(
        displayData.invoice["成本轉移"]
      ).map((key) => {
        return {
          單位: key,
          金額: displayData.invoice["成本轉移"][key],
        };
      });
      displayData.invoice["收入轉移"] = Object.keys(
        displayData.invoice["收入轉移"]
      ).map((key) => {
        return {
          單位: key,
          金額: displayData.invoice["收入轉移"][key],
        };
      });
      displayData.invoice["列數"] = Math.max(
        displayData.invoice["成本轉移"].length,
        displayData.invoice["收入轉移"].length
      );
      isLoading.value = false;
    };

    // Download
    const downloadHtmlDataDepartment = ref<string>("業務部");
    const downloadHtmlData = () => {
      let htmlString = "<html><head><meta charset='utf-8'>";
      htmlString += "<style>";
      htmlString += `
        .gray-block {
          background-color: #CCCCCC;
        }
        .sign-sheet-row {
          background-color: #FEFEFE;
          text-align: center;
        }
        .repair-sheet-row {
          background-color: #FFDAA7;
          text-align: center;
        }
        .parts-row {
          background-color: #C6EAB0;
          text-align: center;
        }
      `;
      htmlString += "</style>";
      htmlString += "</head><body>";
      htmlString +=
        "<h1>" + downloadHtmlDataDepartment.value + "內部計價明細</h1>";
      htmlString += "<h2>篩選條件</h2>";
      htmlString += "<ul>";
      htmlString += "<li>日期: ";
      htmlString += rangePickerValue.value
        ? "" +
          rangePickerValue.value[0].format("YYYY-MM-DD") +
          " ~ " +
          rangePickerValue.value[1].format("YYYY-MM-DD")
        : "";
      htmlString += "</li>";
      htmlString += "<li>簽單選擇: ";
      htmlString += signSheetTypeFilter.value.join(", ");
      htmlString += "</li>";
      htmlString += "<li>帳戶選擇: ";
      htmlString += signSheetAccountFilter.value;
      htmlString += "</li>";
      htmlString += "<li>客戶查詢: ";
      htmlString += customerSearchValue.value;
      htmlString += "</li>";
      htmlString += "</ul>";

      htmlString += "<h2>統計</h2>";
      htmlString += "<ul>";
      htmlString += "<li>簽單總數: ";
      htmlString += displayData.invoice["簽單總數"];
      htmlString += "</li>";
      htmlString += "<li>成本轉移: ";
      htmlString += displayData.invoice["成本轉移"].reduce(
        (acc: any, cur: any) => {
          return (
            acc + (cur.單位 == downloadHtmlDataDepartment.value ? cur.金額 : 0)
          );
        },
        0
      );
      htmlString += "</li>";
      htmlString += "<li>收入轉移: ";
      htmlString += displayData.invoice["收入轉移"].reduce(
        (acc: any, cur: any) => {
          return (
            acc + (cur.單位 == downloadHtmlDataDepartment.value ? cur.金額 : 0)
          );
        },
        0
      );
      htmlString += "</li>";
      htmlString += "</ul>";

      htmlString += "<h2>計價明細</h2>";
      htmlString += "<table border='1' style='border-collapse: collapse'>";
      htmlString += "<thead>";
      htmlString += "<tr>";
      htmlString +=
        "<th class='sign-sheet-row' rowspan='3'>客戶名稱</th>" +
        "<th class='sign-sheet-row'>日期</th>" +
        "<th class='sign-sheet-row'>簽單號碼</th>" +
        "<th class='sign-sheet-row'>成本轉移</th>" +
        "<th class='sign-sheet-row'>收入轉移</th>" +
        "<th class='sign-sheet-row'>註記</th>";
      htmlString += "</tr>";
      htmlString += "<tr>";
      htmlString +=
        // "<th class='gray-block'></th>" +
        "<th class='repair-sheet-row' rowspan='2'>機號</th>" +
        "<th class='repair-sheet-row'>規格</th>" +
        "<th class='repair-sheet-row'>收費</th>" +
        "<th class='repair-sheet-row' style='text-align: flex-start'>備註</th>" +
        "<th class='repair-sheet-row'></th>";
      htmlString += "</tr>";
      htmlString += "<tr>";
      htmlString +=
        // "<th class='gray-block'></th>" +
        // "<th class='gray-block'></th>" +
        "<th class='parts-row'>零件編號</th>" +
        "<th class='parts-row'>數量</th>" +
        "<th class='parts-row'>規格</th>" +
        "<th class='parts-row'>收費</th>";
      htmlString += "</tr>";
      htmlString += "</thead>";
      htmlString += "<tbody>";
      let copyedDbData = JSON.parse(JSON.stringify(dbData));
      copyedDbData.filteredDisplayData
        .sort((a: any, b: any) => {
          // 以客戶ID排序
          let customerIDA = a.customerName.toString();
          let customerIDB = b.customerName.toString();

          // 如果customerIDA 中有 "老爺"，把他加到 prefix
          if (customerIDA.includes("老爺")) {
            customerIDA = "老爺/" + customerIDA;
          }
          if (customerIDB.includes("老爺")) {
            customerIDB = "老爺/" + customerIDB;
          }

          if (customerIDA.localeCompare(customerIDB) == 0) {
            // 如果客戶ID相同，就比較日期
            let dateA: any = dayjs(a.timestamp.slice(5), "YYYY-MM-DD-HHmmss");
            let dateB: any = dayjs(b.timestamp.slice(5), "YYYY-MM-DD-HHmmss");
            return dateA - dateB;
          } else {
            return customerIDA.localeCompare(customerIDB);
          }
        })
        .forEach((row: any) => {
          let customerNameRowSpan =
            1 +
            row.repairRows.reduce(
              (acc: any, cur: any) => acc + cur.parts.length + 1,
              0
            );
          htmlString += "<tr style='border-top: thick double'>";
          // 把 customerName 中的 "-" 用 <br /> 呈現
          let splitCustomerName = row.customerName.split("-").join("<br />");

          htmlString +=
            "<td class='sign-sheet-row' rowspan='" +
            customerNameRowSpan +
            "'>" +
            splitCustomerName +
            // "(" +
            // row.customerID +
            // ")" +
            "</td>";
          htmlString +=
            "<td class='sign-sheet-row'>" +
            dayjs(row.timestamp.substring(5), "YYYY-MM-DD-HHmmss").format(
              "YYYY/MM/DD"
            ) +
            "</td>";
          htmlString += "<td class='sign-sheet-row'>" + row.timestamp + "</td>";
          htmlString +=
            "<td class='sign-sheet-row'>" +
            row.成本轉移.reduce((acc: any, cur: any) => {
              return (
                acc +
                (cur.單位 == downloadHtmlDataDepartment.value ? cur.金額 : 0)
              );
            }, 0) +
            "</td>";
          htmlString +=
            "<td class='sign-sheet-row'>" +
            row.收入轉移.reduce((acc: any, cur: any) => {
              return (
                acc +
                (cur.單位 == downloadHtmlDataDepartment.value ? cur.金額 : 0)
              );
            }, 0) +
            "</td>";
          htmlString +=
            "<td class='sign-sheet-row'>" +
            (row.customerNote == ""
              ? ""
              : "(簽單備註: " + row.customerNote + ")<br />") +
            row.備註 +
            "</td>";
          htmlString += "</tr>";
          row.repairRows.forEach((repairRow: any) => {
            let partsRowSpan = repairRow.parts.length + 1;
            htmlString += "<tr>";
            // htmlString += "<td class='gray-block'></td>";
            htmlString +=
              "<td class='repair-sheet-row' rowspan='" +
              partsRowSpan +
              "'>" +
              repairRow.machineID +
              "</td>";
            htmlString +=
              "<td class='repair-sheet-row'>" + repairRow.machineName + "</td>";
            htmlString +=
              "<td class='repair-sheet-row'>" +
              repairRow.parts.reduce(
                (acc: any, cur: any) =>
                  acc + parseInt(cur.partsPrice) * parseInt(cur.partsCount),
                0
              ) +
              "</td>";
            htmlString +=
              "<td class='repair-sheet-row'>" + repairRow.description + "</td>";
            htmlString += "<td class='repair-sheet-row'></td>";
            htmlString += "</tr>";
            repairRow.parts.forEach((subItem: any) => {
              htmlString += "<tr>";
              // htmlString += "<td class='gray-block'></td>";
              // htmlString += "<td class='gray-block'></td>";
              htmlString +=
                "<td class='parts-row'>" + subItem.partsID + "</td>";
              htmlString +=
                "<td class='parts-row'>" + subItem.partsCount + "</td>";
              htmlString +=
                "<td class='parts-row'>" + subItem.partsName + "</td>";
              htmlString +=
                "<td class='parts-row'>" +
                parseInt(subItem.partsPrice, 10) +
                "</td>";
              htmlString += "</tr>";
            });
          });
        });

      const anchor = document.createElement("a");
      anchor.href =
        "data:text/html;charset=utf-8," + encodeURIComponent(htmlString);
      anchor.target = "_blank";
      anchor.download =
        "內部計價-" + downloadHtmlDataDepartment.value + ".html";
      anchor.click();
      // remove anchor
      setTimeout(() => {
        anchor.remove();
      }, 1000);
    };

    return {
      // lib
      dayjs,
      locale,
      // data
      dbData,
      displayData,
      onChangeAnyFilter,
      isLoading,
      // static
      signSheetColumns,
      repairSheetColumns,
      partsColumns,
      balanceTransferOption,
      signSheetTypeFilterOption,
      signSheetAccountFilterOption,
      // modal data
      transerSettingVisible,
      confirmLoading,
      currentModifyingtranserSetting,
      onOpenTranserSetting,
      onUpdateCostTransferSetting,
      currentSettingAddRow,
      currentSettingDeleteRow,
      // Filter
      rangePickerValue,
      signSheetTypeFilter,
      signSheetAccountFilter,
      customerSearchValue,
      // download
      downloadHtmlData,
      downloadHtmlDataDepartment,
      // customerSearchValue,
      // rangePickerValue,
      // strictCompareMode,
      // costForLaborInternal,
      // discountForCost,
    };
  },
});
