import { createRouter, createWebHistory, RouteRecordRaw } from "vue-router";
import SignSheetViewerView from "../views/SignSheetViewerView.vue";
import MachineHistoryViewerView from "../views/MachineHistoryViewerView.vue";
import MachineHistoryRwdView from "../views/MachineHistoryRwdView.vue";
import PartsViewerView from "../views/PartsViewerView.vue";
import CleanerViewerView from "../views/CleanerViewerView.vue";
import ProfieCenterCostViewerView from "../views/ProfitCenterCostViewerView.vue";
import CallCenterMainViewerView from "../views/CallCenterMainViewerView.vue";
import CleanerSettingViewerView from "../views/CleanerSettingViewerView.vue";
import FactorySchedulerView from "@/views/FactorySchedulerView.vue";
import MaterialStockViewerView from "@/views/MaterialStockViewerView.vue";
import ManufacturerOrderViewerView from "@/views/ManufacturerOrderViewerView.vue";
import LoginView from "@/views/LoginView.vue";
import auth from "@/store/auth";

const routes: Array<RouteRecordRaw> = [
  {
    path: "/login",
    name: "login",
    component: LoginView,
  },
  {
    // userInputPassword / userUnifiedID used to be injected here via GAS
    // HtmlService scriptlets ("<?!= userInputPassword ?>"). The static
    // frontend has no server-side templating, so these views now read the
    // logged-in identity from the auth store instead of route props.
    path: "/sign-sheet-view",
    name: "SignSheetViewerView",
    component: SignSheetViewerView,
  },
  {
    path: "/machine-history",
    name: "machine-history",
    component: MachineHistoryRwdView,
  },
  {
    // 舊機器履歷查詢，目前沒有任何使用到他
    path: "/machine-history-legacy",
    name: "machine-history-legacy",
    component: MachineHistoryViewerView,
  },
  {
    path: "/parts-view",
    name: "parts-view",
    component: PartsViewerView,
  },
  {
    path: "/cleaner-view",
    name: "cleaner-view",
    component: CleanerViewerView,
  },
  {
    path: "/profit-center-cost-view",
    name: "profit-center-cost-view",
    component: ProfieCenterCostViewerView,
  },
  {
    path: "/call-center-main-view",
    name: "call-center-main-view",
    component: CallCenterMainViewerView,
  },
  {
    path: "/cleaner-sales-setting-view",
    name: "cleaner-sales-setting-view",
    component: CleanerSettingViewerView,
  },
  {
    path: "/factory-scheduler-view",
    name: "factory-scheduler-view",
    component: FactorySchedulerView,
  },
  {
    path: "/material-stock-view",
    name: "material-stock-view",
    component: MaterialStockViewerView,
  },
  {
    path: "/manufacturing-order-view",
    name: "manufacturing-order-view",
    component: ManufacturerOrderViewerView,
  },
  {
    path: "/about",
    name: "about",
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () =>
      import(/* webpackChunkName: "about" */ "../views/AboutView.vue"),
  },
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
});

router.beforeEach((to) => {
  if (to.name !== "login" && !auth.isLoggedIn) {
    return { name: "login", query: { redirect: to.fullPath } };
  }
  return true;
});

export default router;
