
import { defineComponent, reactive, watchEffect, ref, onMounted } from "vue";
import { Table } from "ant-design-vue";
import {} from "@ant-design/icons-vue";
import { fetchToolsData } from "@/api/tools-data";
import dayjs from "dayjs";
import { RedoOutlined } from "@ant-design/icons-vue";
const columnsParts = [
  {
    title: "品號",
    dataIndex: "品號",
    key: "品號",
    sorter: (a: any, b: any) => a.品號.localeCompare(b.品號),
    defaultSortOrder: "ascend",
  },
  {
    title: "名稱",
    dataIndex: "名稱",
    key: "名稱",
    sorter: (a: any, b: any) => a.名稱.localeCompare(b.名稱),
  },
  { title: "單位", dataIndex: "單位", key: "單位" },
  { title: "庫存", dataIndex: "庫存", key: "庫存" },
  {
    title: "未出帳",
    dataIndex: "未出帳",
    key: "未出帳",
    sorter: (a: any, b: any) => a.未出帳 - b.未出帳,
  },
];
const columnsPartsDetail = [
  {
    title: "庫別代號",
    dataIndex: "stockID",
    key: "stockID",
    width: 150,
    sorter: (a: any, b: any) => a.stockID.localeCompare(b.stockID),
    defaultSortOrder: "ascend",
  },
  {
    title: "庫別名稱",
    dataIndex: "stockName",
    key: "stockName",
    width: 200,
  },
  {
    title: "庫存",
    dataIndex: "partsNum",
    key: "partsNum",
    width: 200,
    sorter: (a: any, b: any) => a.partsNum.localeCompare(b.partsNum),
  },
  {
    title: "未出帳",
    dataIndex: "partsUsedToday",
    key: "partsUsedToday",
    width: 200,
  },
];

const columnsStockNames = [
  {
    title: "庫別代號",
    dataIndex: "庫別代號",
    key: "庫別代號",
    width: 200,
    sorter: (a: any, b: any) => a.庫別代號.localeCompare(b.庫別代號),
    defaultSortOrder: "descend",
  },
  {
    title: "庫別名稱",
    dataIndex: "庫別名稱",
    key: "庫別名稱",
    width: 200,
    sorter: (a: any, b: any) => a.庫別名稱.localeCompare(b.庫別名稱),
  },
  { title: "零件種類", dataIndex: "零件種類", key: "零件種類" },
];
const columnsStockNamesDetail = [
  {
    title: "品號",
    dataIndex: "partsID",
    key: "partsID",
    sorter: (a: any, b: any) => a.partsID.localeCompare(b.partsID),
    defaultSortOrder: "ascend",
  },
  {
    title: "名稱",
    dataIndex: "partsName",
    key: "partsName",
    sorter: (a: any, b: any) => a.partsName.localeCompare(b.partsName),
  },
  { title: "單位", dataIndex: "partsUnit", key: "partsUnit", width: 50 },
  {
    title: "庫存",
    dataIndex: "partsNum",
    key: "partsNum",
    sorter: (a: any, b: any) => a.partsNum - b.partsNum,
  },
  { title: "未出帳", dataIndex: "partsUsedToday", key: "partsUsedToday" },
];

interface ShowData {
  data: any[];
  mapFromPartsID: Map<string, any>;
  mapFromStockID: Map<string, any>;
  rawData: any[] | null;
}

export default defineComponent({
  name: "PartsViewer",
  components: {
    ATable: Table,
    // DownloadOutlined,
    RedoOutlined,
    // DeleteOutlined,
  },
  props: {},
  setup() {
    // Display Data Structure
    const rawData = ref<any[]>([]);
    const filteredData = ref<any[]>([]);
    const data: ShowData = reactive({
      data: [],
      mapFromPartsID: new Map(),
      mapFromStockID: new Map(),
      rawData: null,
    });
    const dataFilterByPartsID: any = ref(true);
    const isLoading: any = ref(false);

    // loading data
    onMounted(() => {
      reloadData();
    });

    const reloadData = () => {
      isLoading.value = true;
      fetchToolsData((ret: any): void => {
        rawData.value = ret;
        onChangeAnyFilter();
      });
    };

    // Any Filter
    const partsSearchValue = ref<string>();
    const includeZeroStock = ref<boolean>(false);

    const onChangeAnyFilter = () => {
      filteredData.value = rawData.value.filter((row: any) => {
        if (!includeZeroStock.value) {
          if (row.partsNum == 0) return false;
        }

        if (partsSearchValue.value) {
          if (dataFilterByPartsID.value) {
            // Filter Parts ID
            const cuPartsID: string = row.partsID;
            const cuPartsName: string = row.partsName;
            if (
              !cuPartsID ||
              !cuPartsName ||
              !(
                cuPartsID.includes(partsSearchValue.value) ||
                cuPartsName.includes(partsSearchValue.value)
              )
            ) {
              return false;
            }
          } else {
            // Filter Stock Name
            const cuStockID: string = row.stockID;
            const cuStockName: string = row.stockName;
            if (
              !cuStockID ||
              !cuStockName ||
              !(
                cuStockID.includes(partsSearchValue.value) ||
                cuStockName.includes(partsSearchValue.value)
              )
            ) {
              return false;
            }
          }
        }

        // Filter Enginner Name
        // if (engineerSelectedValue.value) {
        //   if (row.engineerID != engineerSelectedValue.value) return false;
        // }
        // // Filter Time Range
        // let strlist = row.timestamp.split("-");
        // let dayjsObj = dayjs(
        //   strlist[1] + strlist[2] + strlist[3] + strlist[4],
        //   "YYYYMMDDHHmmss"
        // );
        // if (rangePickerValue.value) {
        //   if (rangePickerValue.value[0].startOf("date") > dayjsObj)
        //     return false;
        //   if (dayjsObj > rangePickerValue.value[1].endOf("date")) return false;
        // }

        // if not filtered
        return true;
      });
    };

    watchEffect(() => {
      data.mapFromPartsID.clear();
      data.mapFromStockID.clear();

      filteredData.value.map((row: any) => {
        if (!data.mapFromPartsID.has(row.partsID)) {
          data.mapFromPartsID.set(row.partsID, []);
        }
        if (!data.mapFromStockID.has(row.stockID)) {
          data.mapFromStockID.set(row.stockID, []);
        }
        data.mapFromPartsID.get(row.partsID).push(row);
        data.mapFromStockID.get(row.stockID).push(row);
      });

      if (dataFilterByPartsID.value) {
        console.log("品號模式");
        // 零件品號為主要的 key
        data.data = [];
        data.mapFromPartsID.forEach((value: any, key: any) => {
          if (key == "7EGRO10701020") {
            console.log(value);
          }
          data.data.push({
            品號: key,
            名稱: value[0].partsName,
            單位: value[0].partsUnit,
            庫存: value
              .map((row: any) => parseFloat(row.partsNum))
              .reduce((a: any, b: any) => a + b, 0),
            未出帳: value
              .map((row: any) => parseFloat(row.partsUsedToday))
              .reduce((a: any, b: any) => a + b, 0),
            庫存明細: value,
          });
        });
      } else {
        // 庫位為主要的 key
        data.data = [];
        data.mapFromStockID.forEach((value: any, key: any) => {
          data.data.push({
            庫別代號: key,
            庫別名稱: value[0].stockName,
            零件種類: value.length,
            庫存明細: value,
          });
        });
      }

      isLoading.value = false;
    });

    return {
      data,
      reloadData,
      isLoading,
      columnsParts,
      columnsPartsDetail,
      columnsStockNames,
      columnsStockNamesDetail,
      partsSearchValue,
      onChangeAnyFilter,
      dataFilterByPartsID,
      includeZeroStock,
    };
  },
});
