import { callApi } from "./client";

export function fetchInnerCostData(callback: any) {
  callApi("fetchInnerCostData")
    .then(callback)
    .catch(() => {
      console.log("fetchInnerCostData Failed");
    });
}

export function updateTransferSettingData(data: any, callback: any) {
  callApi("updateTransferSettingData", { data })
    .then(callback)
    .catch(() => {
      console.log("updateTransferSettingData Failed");
    });
}
