
import {
  defineComponent,
  ref,
  reactive,
  onMounted,
  computed,
  watch,
  watchEffect,
} from "vue";
import locale from "ant-design-vue/es/date-picker/locale/zh_TW";
import {
  PlusOutlined,
  DeleteOutlined,
  WarningOutlined,
} from "@ant-design/icons-vue";
import { message, notification } from "ant-design-vue";
import {
  fetchProductData,
  updateScheduleProjectSetting,
} from "@/api/factory-scheduler";
import dayjs from "dayjs";
import "dayjs/locale/zh-tw";
import ProductSelector from "@/components/erp-data-selector/ProductSelector.vue";

interface bakeScheduleChunk {
  bomRequiredItemUid: string;
  name: string;
  uid: string;
  chunkDate: string;
  quantityType: number;
  orderOnTheDay: number;
  quantity: number;
}

interface bomRequiredItem {
  productRequiredUid: string;
  uid: string;
  materialId: string;
  materialName: string;
  materialSpec: string;
  materialType: string;
  materialQuantityRequired: number;
  scheduleChunkUids: string[];
}

interface productRequiredItem {
  uid: string;
  productId: string;
  productName: string;
  productSpec: string;
  productAlias: string;
  productionLine: string; // 使用者在輸入的時候指定的包裝線別
  productRequiredDate: string; // 使用者在輸入的時候指定的日期
  quantityRequired: number;
  orderOnTheDay: number;
  bom: bomRequiredItem[];
}

interface ProductLineDataMapping {
  [key: string]: any;
}

const productLineDataMapping: ProductLineDataMapping = {
  "101": { color: "rgb(218, 238, 227)", name: "量產" },
  "102": { color: "rgb(126, 250, 144)", name: "精品" },
  "201": { color: "rgb(204, 204, 255)", name: "豆-自動" },
  "202": { color: "rgb(204, 255, 204)", name: "豆-成形" },
  "203": { color: "rgb(255, 204, 255)", name: "濾泡自動" },
  "204": { color: "rgb(255, 255, 204)", name: "濾泡成盒" },
  "205": { color: "rgb(204, 255, 255)", name: "氮氣研磨" },
  "206": { color: "rgb(255, 204, 204)", name: "研磨粉" },
  "207": { color: "rgb(255, 204, 100)", name: "成形袋手工" },
};

const bakeChunkQuantityTypes = ref([
  {
    value: 96,
    label: "大鍋",
  },
  {
    value: 48,
    label: "小鍋",
  },
  {
    value: 1,
    label: "公斤",
  },
]);
export default defineComponent({
  name: "FactoryScheduler",
  components: {
    PlusOutlined,
    DeleteOutlined,
    WarningOutlined,
    ProductSelector,
  },
  props: {},
  setup() {
    dayjs.locale("zh-tw");

    // #region 資料初始化
    const dbProductData: any = ref([]);
    const dbBomMapping: any = ref({});
    const cuProjAllRequirementData: any = ref<productRequiredItem[]>([]);
    const cuFirstOrderRequirementData: any = ref<bakeScheduleChunk[]>([]);
    const isLoadingDataFromDb = ref(false);
    const cuSelectedDay = ref(dayjs());

    onMounted(() => {
      isLoadingDataFromDb.value = true;
      fetchProductData("排程", (data: any): void => {
        dbProductData.value = data.產品;
        if (data.設定資料.需求資料 === undefined) {
          data.設定資料.需求資料 = [];
          data.設定資料.烘焙資料 = [];
        }
        cuProjAllRequirementData.value = data.設定資料.需求資料;
        cuFirstOrderRequirementData.value = data.設定資料.烘焙資料;
        // 把 BOM 資料轉換成以品號為 key 的物件
        for (let i = 0; i < data.BOM.length; i++) {
          if (!dbBomMapping.value[data.BOM[i][0]]) {
            dbBomMapping.value[data.BOM[i][0]] = [];
          }
          dbBomMapping.value[data.BOM[i][0]].push(data.BOM[i]);
        }
        // console.log(bomData.value);
        // console.log(dbProductData.value);
        isLoadingDataFromDb.value = false;
      });
    });
    // #endregion 資料初始化

    // #region 資料上傳
    const needUpdateData = ref(false);
    const onUploadData = () => {
      updateScheduleProjectSetting(
        "排程",
        {
          需求資料: cuProjAllRequirementData.value,
          烘焙資料: cuFirstOrderRequirementData.value,
        },
        () => {
          message.success("儲存成功");
          needUpdateData.value = false;
        }
      );
    };
    // #endregion 資料上傳

    // #region 日曆相關
    const currentStatMonth: any = ref(dayjs().format("YYYY-MM"));
    const getScheduleByDate = (
      currentDateDayjs: any,
      isBakeryMode: boolean
    ) => {
      let data: any = [];
      if (!isBakeryMode) {
        data = cuProjAllRequirementData.value
          .filter(
            (item: productRequiredItem) =>
              item.productRequiredDate === currentDateDayjs.format("YYYY-MM-DD")
          )
          .sort(
            (a: productRequiredItem, b: productRequiredItem) =>
              a.orderOnTheDay - b.orderOnTheDay
          );
      } else {
        data = cuFirstOrderRequirementData.value
          .filter(
            (item: bakeScheduleChunk) =>
              item.chunkDate === currentDateDayjs.format("YYYY-MM-DD")
          )
          .sort(
            (a: bakeScheduleChunk, b: bakeScheduleChunk) =>
              a.orderOnTheDay - b.orderOnTheDay
          );
      }
      return data;
    };
    const onChangeCalendarSelectedDay = (selectedDay: any) => {
      // 如果選擇的日期不是當月，就重新計算統計資料，並清空主產品顏色對應
      if (selectedDay.format("YYYY-MM") !== currentStatMonth.value) {
        reCalculateStatisticalData();
        currentMainProductColorMapping.value = {};
      }
    };
    // 以下為拖曳相關
    const draggingEvent: any = ref(null);
    const ghostEvent: any = ref(null);
    const getDateFromPosition = (x: number, y: number, oriDateDayjs: any) => {
      let cell = document.elementFromPoint(x, y);
      if (!cell) {
        return oriDateDayjs;
      }
      // 往下找到他的 parent 是不是 td
      while (cell.tagName !== "TD" && cell.parentElement) {
        cell = cell.parentElement;
      }
      if (cell.tagName === "TD") {
        let date = cell.getAttribute("title");
        if (date) {
          console.log(date);
          return dayjs(date, "YYYY-MM-DD");
        }
      }
      return oriDateDayjs;
    };
    const getChunkIdFromPosition = (x: number, y: number, isChunk: boolean) => {
      let chunkLi = document.elementFromPoint(x, y);
      console.log(chunkLi);
      if (!chunkLi) {
        return null;
      }

      let uid = null;
      if (isChunk) {
        // 其 parent 是 div.ant-row
        chunkLi = chunkLi.parentElement;
        // 確認此 div 的 id 是否有 uid
        uid = chunkLi?.id;
        if (!uid) {
          return null;
        }
      } else {
        // 不取 parent
        uid = chunkLi?.id;
        if (!uid) {
          return null;
        }
      }
      return uid;
    };
    const startDragEvent = (
      mouseDownEvt: any,
      date: any,
      eventData: any,
      isBakeryMode: boolean
    ) => {
      draggingEvent.value = eventData;

      ghostEvent.value = {
        ...eventData,
        left: mouseDownEvt.clientX,
        top: mouseDownEvt.clientY,
        isBakeryMode: isBakeryMode,
      };

      document.body.style.userSelect = "none"; // 禁用文本選擇

      const onMouseMove = (e: any) => {
        if (ghostEvent.value) {
          ghostEvent.value.left = e.clientX;
          ghostEvent.value.top = e.clientY;
        }
      };

      const onMouseUp = (e: any) => {
        // 計算移動量
        let dx = e.clientX - mouseDownEvt.clientX;
        let dy = e.clientY - mouseDownEvt.clientY;
        let distance = Math.sqrt(dx * dx + dy * dy);
        if (draggingEvent.value) {
          // 移動超過 10px 才算拖曳
          if (distance > 10) {
            const targetDate = getDateFromPosition(e.clientX, e.clientY, date);
            // 拖曳到不合法的cell (回傳date物件)
            // 或是拖曳到同一天
            // 或是拖到不同月份
            // 就不做事
            if (
              targetDate.format("YYYY-MM-DD") !== date.format("YYYY-MM-DD") &&
              targetDate.format("YYYY-MM") === date.format("YYYY-MM")
            ) {
              // 拖曳到不同日期，所以是改變日期
              changeEventDate(
                draggingEvent.value.uid,
                targetDate,
                isBakeryMode
              );
            }
            if (targetDate.format("YYYY-MM-DD") === date.format("YYYY-MM-DD")) {
              // 拖到同一天，所以是改變順序
              const targetChunkId = getChunkIdFromPosition(
                e.clientX,
                e.clientY,
                isBakeryMode
              );
              if (targetChunkId && targetChunkId !== draggingEvent.value.uid) {
                console.log(
                  targetChunkId,
                  draggingEvent.value.uid,
                  isBakeryMode
                );
                swapChunckIdOrder(
                  targetChunkId,
                  draggingEvent.value.uid,
                  isBakeryMode
                );
              }
            }
          }
          draggingEvent.value = null;
          ghostEvent.value = null;
          document.removeEventListener("mousemove", onMouseMove);
          document.removeEventListener("mouseup", onMouseUp);
          document.body.style.userSelect = "";
        }
      };

      document.addEventListener("mousemove", onMouseMove);
      document.addEventListener("mouseup", onMouseUp);
    };
    const changeEventDate = (
      eventUid: any,
      newDate: any,
      isBakeryMode: boolean
    ) => {
      if (isBakeryMode) {
        // 這是烘焙排程
        let targetChunks = cuFirstOrderRequirementData.value.find(
          (item: bakeScheduleChunk) => item.uid === eventUid
        );
        if (!targetChunks) {
          message.error("找不到對應的烘焙排程");
          return;
        }
        // 使用 targetChunks.bomRequiredItemUid 找到對應的 productRequiredItem
        let targetProduct = cuProjAllRequirementData.value.filter(
          (item: productRequiredItem) =>
            item.bom.find(
              (bomItem: bomRequiredItem) =>
                bomItem.uid === targetChunks.bomRequiredItemUid
            )
        )[0];
        if (!targetProduct) {
          message.error("從烘焙排程找不到對應的產品");
          return;
        }
        // 檢查 newDate 的日期是否在 targetProduct 的日期前(包含當天)
        let isDateValid = newDate.isBefore(
          dayjs(targetProduct.productRequiredDate).add(1, "day")
        );
        if (!isDateValid) {
          message.error("烘焙日期不可在產品日期之後");
          return;
        }

        // 找到目標日期的最大 order
        let maxOrder = findMaxOrderOnTheDay(
          newDate.format("YYYY-MM-DD"),
          cuFirstOrderRequirementData.value,
          isBakeryMode
        );
        // newOrderOnTheDay 是最大的 order + random 1 - 10000
        let newOrderOnTheDay = maxOrder + Math.floor(Math.random() * 10000);
        targetChunks.orderOnTheDay = newOrderOnTheDay;
        // 更新日期
        targetChunks.chunkDate = newDate.format("YYYY-MM-DD");
      } else {
        let targetEvent = cuProjAllRequirementData.value.find(
          (item: any) => item.uid === eventUid
        );
        if (!targetEvent) {
          message.error("找不到對應的排程");
          return;
        }
        // 要先取得當天的最大 order 再改日期
        let maxOrderOnTheDay = findMaxOrderOnTheDay(
          newDate.format("YYYY-MM-DD"),
          cuProjAllRequirementData.value,
          isBakeryMode
        );

        targetEvent.productRequiredDate = newDate.format("YYYY-MM-DD");
        targetEvent.orderOnTheDay =
          maxOrderOnTheDay + Math.floor(Math.random() * 10000);
        let copiedProjAllRequirementData = JSON.parse(
          JSON.stringify(cuProjAllRequirementData.value)
        );
        let copiedFirstOrderRequirementData = JSON.parse(
          JSON.stringify(cuFirstOrderRequirementData.value)
        );

        // 重新計算 chunk
        copiedFirstOrderRequirementData = removeChunkByProductScheduleUid(
          targetEvent.uid,
          copiedProjAllRequirementData,
          copiedFirstOrderRequirementData
        );
        addChunksByproductScheduleUid(
          targetEvent.uid,
          copiedProjAllRequirementData,
          copiedFirstOrderRequirementData
        );
        cuProjAllRequirementData.value = copiedProjAllRequirementData;
        cuFirstOrderRequirementData.value = copiedFirstOrderRequirementData;
        // reCalculateStatisticalData();
      }
      needUpdateData.value = true;
    };
    const swapChunckIdOrder = (aId: any, bId: any, isChunk: boolean) => {
      if (isChunk) {
        let targetAChunks = cuFirstOrderRequirementData.value.find(
          (item: bakeScheduleChunk) => item.uid === aId
        );
        let targetBChunks = cuFirstOrderRequirementData.value.find(
          (item: bakeScheduleChunk) => item.uid === bId
        );
        if (!targetAChunks || !targetBChunks) {
          message.error("找不到對應的烘焙排程");
          return;
        }
        let tempOrder = targetAChunks.orderOnTheDay;
        targetAChunks.orderOnTheDay = targetBChunks.orderOnTheDay;
        targetBChunks.orderOnTheDay = tempOrder;
        needUpdateData.value = true;
        return;
      } else {
        let targetAEvent = cuProjAllRequirementData.value.find(
          (item: any) => item.uid === aId
        );
        let targetBEvent = cuProjAllRequirementData.value.find(
          (item: any) => item.uid === bId
        );
        if (!targetAEvent || !targetBEvent) {
          message.error("找不到對應的排程");
          return;
        }
        let tempOrder = targetAEvent.orderOnTheDay;
        targetAEvent.orderOnTheDay = targetBEvent.orderOnTheDay;
        targetBEvent.orderOnTheDay = tempOrder;
        needUpdateData.value = true;
        return;
      }
    };

    // 以下為日曆內容高度、寬度相關
    const calendarContentHeight = ref(120);
    const calendarContentWidth = ref(100);
    watch(
      [calendarContentHeight, calendarContentWidth],
      ([newHeight, newWidth]) => {
        document.documentElement.style.setProperty(
          "--calendar-content-height",
          `${newHeight}px`
        );
        document.documentElement.style.setProperty(
          "--calendar-content-width",
          `${newWidth * 7}px`
        );
      }
    );
    // #endregion 日曆相關

    // #region 編輯日排程
    const isEditScheduleModalOpen = ref(false);
    const cuSelectedDaySchedules: any = ref<productRequiredItem[]>([]);
    const reComputedSelectedDaySchedules = () => {
      // 把 cuProjAllRequirementData 掃過一遍，找出當天的排程
      // 並且複製一份到 cuSelectedDaySchedules
      cuSelectedDaySchedules.value = [];
      if (cuSelectedDay.value !== null) {
        for (var i = 0; i < cuProjAllRequirementData.value.length; i++) {
          if (
            cuProjAllRequirementData.value[i].productRequiredDate ===
            cuSelectedDay.value.format("YYYY-MM-DD")
          ) {
            cuSelectedDaySchedules.value.push(
              JSON.parse(JSON.stringify(cuProjAllRequirementData.value[i]))
            );
          }
        }
        // 使用 orderOnTheDay 排序
        cuSelectedDaySchedules.value.sort(
          (a: productRequiredItem, b: productRequiredItem) =>
            a.orderOnTheDay - b.orderOnTheDay
        );
      }
    };
    const onEditOneDaySchedule = (selectedDay: any) => {
      // 使用者點選日曆上的日期，開啟編輯排程的 modal
      isEditScheduleModalOpen.value = true;
      cuSelectedDay.value = selectedDay;
      reComputedSelectedDaySchedules();
    };
    const onRemoveSchedule = (uid: string) => {
      // 使用者點選刪除排程
      cuSelectedDaySchedules.value = cuSelectedDaySchedules.value.filter(
        (item: any) => item.uid !== uid
      );
    };
    const onConfirmEditSchedule = () => {
      // 使用者按下確認編輯排程後
      // 先複製一份 cuProjAllRequirementData
      let copiedProjAllRequirementData = JSON.parse(
        JSON.stringify(cuProjAllRequirementData.value)
      );
      let copiedFirstOrderRequirementData = JSON.parse(
        JSON.stringify(cuFirstOrderRequirementData.value)
      );
      // 更新 cuProjAllRequirementData
      for (let i = 0; i < cuSelectedDaySchedules.value.length; i++) {
        // 對於每一個排程，找到對應的排程，更新數量及別名
        let targetSchedule = copiedProjAllRequirementData.find(
          (item: any) => item.uid === cuSelectedDaySchedules.value[i].uid
        );
        if (targetSchedule) {
          // 先確認使用者有沒有更改數量或日期
          let hasUserChangeAmountOrDate =
            targetSchedule.quantityRequired !==
              cuSelectedDaySchedules.value[i].quantityRequired ||
            targetSchedule.productRequiredDate !==
              cuSelectedDaySchedules.value[i].productRequiredDate;

          // 更新數量及別名
          targetSchedule.quantityRequired =
            cuSelectedDaySchedules.value[i].quantityRequired;
          targetSchedule.productAlias =
            cuSelectedDaySchedules.value[i].productAlias;
          targetSchedule.productionLine =
            cuSelectedDaySchedules.value[i].productionLine;
          // targetSchedule.productColor =
          //   cuSelectedDaySchedules.value[i].productColor;
          console.log("copiedFirstOrderRequirementData");
          console.log(copiedFirstOrderRequirementData);

          if (hasUserChangeAmountOrDate) {
            // 如果有更改數量或日期，就重新計算 BOM
            copiedFirstOrderRequirementData = removeChunkByProductScheduleUid(
              targetSchedule.uid,
              copiedProjAllRequirementData,
              copiedFirstOrderRequirementData
            );
            addChunksByproductScheduleUid(
              targetSchedule.uid,
              copiedProjAllRequirementData,
              copiedFirstOrderRequirementData
            );
          }
        } else {
          // 如果找不到，代表是新增的排程
          copiedProjAllRequirementData.push(cuSelectedDaySchedules.value[i]);
          // 重新計算 BOM
          addChunksByproductScheduleUid(
            cuSelectedDaySchedules.value[i].uid,
            copiedProjAllRequirementData,
            copiedFirstOrderRequirementData
          );
        }
      }
      // 移除已經不存在的排程
      // 先複製一份 CopiedProjAllRequirementData 當做參考
      let referenceCopiedProjAllRequirementData = JSON.parse(
        JSON.stringify(copiedProjAllRequirementData)
      );
      referenceCopiedProjAllRequirementData.forEach((item: any) => {
        // 如果不是當天的排程，就保留
        if (
          item.productRequiredDate !== cuSelectedDay.value.format("YYYY-MM-DD")
        ) {
          return;
        }
        // 如果是當天的排程，就看看有沒有在 cuSelectedDaySchedules 中
        let findResult = cuSelectedDaySchedules.value.find(
          (schedule: any) => schedule.uid === item.uid
        );
        // 如果沒找到的話，就從 copiedProjAllRequirementData 中移除
        if (!findResult) {
          // 先移除 Chunk
          copiedFirstOrderRequirementData = removeChunkByProductScheduleUid(
            item.uid,
            copiedProjAllRequirementData,
            copiedFirstOrderRequirementData
          );
          // 再移除排程
          copiedProjAllRequirementData = copiedProjAllRequirementData.filter(
            (schedule: any) => schedule.uid !== item.uid
          );
        }
        // return cuSelectedDaySchedules.value.find(
        //   (schedule: any) => schedule.uid === item.uid
        // );
      });
      cuProjAllRequirementData.value = copiedProjAllRequirementData;
      cuFirstOrderRequirementData.value = copiedFirstOrderRequirementData;

      // 重新計算統計資料
      // reCalculateStatisticalData();

      isEditScheduleModalOpen.value = false;
      needUpdateData.value = true;
    };
    // #endregion 編輯日排程

    // #region 編輯排程屬性
    const isEditSchedulePropertyModalOpen = ref(false);
    const currentChangePropertySchedule: any = ref<productRequiredItem | null>(
      null
    );
    const onEditScheduleProperty = (uid: string) => {
      // 使用者點選編輯排程屬性
      isEditSchedulePropertyModalOpen.value = true;
      // 一定要從 cuSelectedDaySchedules 中找到對應的排程
      const targetSchedule = cuSelectedDaySchedules.value.find(
        (item: any) => item.uid === uid
      );
      if (targetSchedule) {
        currentChangePropertySchedule.value = JSON.parse(
          JSON.stringify(targetSchedule)
        );
      }
    };
    const onSaveProductProperty = () => {
      // 使用者按下確認編輯排程屬性
      const targetSchedule = cuSelectedDaySchedules.value.find(
        (item: any) => item.uid === currentChangePropertySchedule.value.uid
      );
      if (targetSchedule) {
        console.log("currentChangePropertySchedule.value");
        console.log(currentChangePropertySchedule.value);
        console.log("targetSchedule");
        console.log(targetSchedule);
        targetSchedule.productAlias =
          currentChangePropertySchedule.value.productAlias;
        targetSchedule.productionLine =
          currentChangePropertySchedule.value.productionLine;
      }
      isEditSchedulePropertyModalOpen.value = false;
      needUpdateData.value = true;
    };
    // #endregion 編輯排程屬性

    // #region 烘焙模式
    const isScheduleMode = ref(true);
    const currentMainProductColorMapping: any = ref({});
    const toggleGhostOfMainProductColor = (productUid: string) => {
      if (currentMainProductColorMapping.value[productUid]) {
        currentMainProductColorMapping.value[productUid].isGhost =
          !currentMainProductColorMapping.value[productUid].isGhost;
      }
    };
    const currentScreenBakeryProdcutColorMapping: any = computed(() => {
      const thisMonthBeforeOneWeekString = cuSelectedDay.value
        .startOf("month")
        .subtract(1, "week")
        .format("YYYY-MM-DD");
      const thisMonthAfterOneWeekString = cuSelectedDay.value
        .endOf("month")
        .add(1, "week")
        .format("YYYY-MM-DD");
      let currentScreenChunks = cuFirstOrderRequirementData.value.filter(
        (item: bakeScheduleChunk) =>
          item.chunkDate >= thisMonthBeforeOneWeekString &&
          item.chunkDate <= thisMonthAfterOneWeekString
      );
      // 取得這個月所有的 bomRequiredItemUid
      let currentScreenBomRequiredItemUid: any = {};
      currentScreenChunks.forEach((item: bakeScheduleChunk) => {
        if (!currentScreenBomRequiredItemUid[item.bomRequiredItemUid]) {
          currentScreenBomRequiredItemUid[item.bomRequiredItemUid] = {};
        }
      });
      // 把所有的主產品都加入到 currentMainProductColorMapping
      cuProjAllRequirementData.value.forEach((item: productRequiredItem) => {
        item.bom.forEach((bomItem: bomRequiredItem) => {
          // 這個 bomItem 在這個月的排程中
          if (currentScreenBomRequiredItemUid[bomItem.uid]) {
            // 如果這個 bomItem 對應到的主產品
            // 還沒有被指定顏色，就隨機指定一個顏色
            if (!currentMainProductColorMapping.value[item.uid]) {
              let randomColorStr =
                "rgba(" +
                Math.floor(Math.random() * 256) +
                "," +
                Math.floor(Math.random() * 256) +
                "," +
                Math.floor(Math.random() * 256) +
                ",0.5)";
              let displayString =
                (item.productAlias
                  ? item.productAlias
                  : item.productName + " " + item.productSpec) +
                " x " +
                item.quantityRequired +
                " | " +
                item.productRequiredDate;

              // 更新顯示在畫面左邊的主產品顏色對應
              currentMainProductColorMapping.value[item.uid] = {
                mainProductUid: item.uid,
                color: randomColorStr,
                displayName: displayString,
                isGhost: false,
              };
            }
            let mainProductStyle =
              currentMainProductColorMapping.value[item.uid];
            currentScreenBomRequiredItemUid[bomItem.uid] = {
              mainProductUid: mainProductStyle.mainProductUid,
              color: mainProductStyle.color,
              isGhost: mainProductStyle.isGhost,
            };
          }
        });
      });
      return currentScreenBomRequiredItemUid;
    });
    const findMaxOrderOnTheDay = (
      date: string,
      innerCuFirstOrderRequirementData: any,
      isBakeryMode: boolean
    ) => {
      console.log("findMaxOrderOnTheDay");
      let maxOrderOnTheDay = 0;
      if (isBakeryMode) {
        innerCuFirstOrderRequirementData.forEach((item: bakeScheduleChunk) => {
          if (item.chunkDate === date) {
            maxOrderOnTheDay = Math.max(maxOrderOnTheDay, item.orderOnTheDay);
          }
        });
      } else {
        innerCuFirstOrderRequirementData.forEach(
          (item: productRequiredItem) => {
            if (item.productRequiredDate === date) {
              maxOrderOnTheDay = Math.max(maxOrderOnTheDay, item.orderOnTheDay);
            }
          }
        );
      }
      return maxOrderOnTheDay;
    };
    const addChunksByproductScheduleUid = (
      productScheduleUid: string,
      targetAllRequirementData: productRequiredItem[],
      targetFirstOrderRequirementData: bakeScheduleChunk[]
    ) => {
      // 從 cuProjAllRequirementData 中找到這個排程的資料
      const targetProductSchedule = targetAllRequirementData.find(
        (item: any) => item.uid === productScheduleUid
      );
      if (targetProductSchedule === undefined) {
        message.error("calculateNewAddedProductBom 錯誤，排程中無此品號");
        return;
      }

      // 找到這個排程的預設日期
      let chuckDateDefault = dayjs(
        targetProductSchedule.productRequiredDate,
        "YYYY-MM-DD"
      )
        .subtract(0, "day")
        .format("YYYY-MM-DD");
      // 找到這個排程預設日期中最大的 orderOnTheDay
      let maxOrderOnTheDay = findMaxOrderOnTheDay(
        chuckDateDefault,
        targetFirstOrderRequirementData,
        true
      );

      const bomOfProduct = dbBomMapping.value[targetProductSchedule.productId];
      if (bomOfProduct === undefined) {
        message.error("calculateNewAddedProductBom 錯誤，無此品號的 BOM");
        return;
      }

      // 遍歷 BOM，計算原料需求後加入該排程的 bom 中
      bomOfProduct.forEach((bomItem: any) => {
        // 從 dbProductData 中找到這個原料的資料
        const targetMaterial = dbProductData.value.find(
          (item: any) => item[0] === bomItem[2]
        );
        if (targetMaterial === undefined) {
          message.error(
            "calculateNewAddedProductBom 錯誤，無此原料: " + bomItem[2]
          );
          return;
        }
        if (targetMaterial[3] != 102) {
          return;
        }

        let amount =
          (parseFloat(bomItem[4]) /
            parseFloat(bomItem[5]) /
            parseFloat(bomItem[6]) /
            (1 - parseFloat(bomItem[7]))) *
          targetProductSchedule.quantityRequired;
        amount = Math.round(amount * 1000) / 1000; // amount 只取到小數第三位

        let materialUid = Math.random().toString(36).substring(7);
        let newChunkUid = Math.random().toString(36).substring(7);

        // 製作新的 chunk 加入到 targetFirstOrderRequirementData

        // 從 1 到 10000 隨機取一個數字，作為 orderOnTheDay 的 offset
        let randomOrderOnTheDayOffset = Math.floor(Math.random() * 10000);
        targetProductSchedule.bom.push({
          productRequiredUid: productScheduleUid,
          uid: materialUid,
          materialId: bomItem[2],
          materialName: targetMaterial[1],
          materialSpec: targetMaterial[2],
          materialType: targetMaterial[3],
          materialQuantityRequired: amount,
          scheduleChunkUids: [newChunkUid],
        });
        targetFirstOrderRequirementData.push({
          bomRequiredItemUid: materialUid,
          quantityType: 1,
          name: targetMaterial[1],
          uid: newChunkUid,
          chunkDate: chuckDateDefault,
          orderOnTheDay: maxOrderOnTheDay + randomOrderOnTheDayOffset,
          quantity: amount,
        });
      });
    };
    const removeChunkByProductScheduleUid = (
      productScheduleUid: string,
      targetAllRequirementData: productRequiredItem[],
      targetFirstOrderRequirementData: bakeScheduleChunk[]
    ): bakeScheduleChunk[] => {
      // 從 cuFirstOrderRequirementData 中找到這個排程的資料
      const targetProductSchedule = targetAllRequirementData.find(
        (item: productRequiredItem) => item.uid === productScheduleUid
      );
      if (targetProductSchedule === undefined) {
        message.error("removeChunkByProductScheduleUid 錯誤，排程中無此Uid");
        return targetFirstOrderRequirementData;
      }

      // 遍歷 BOM，找到對應的 chunk，然後刪除
      let chunkUidNeedToRemove: string[] = [];
      targetProductSchedule.bom.forEach((bomItem: bomRequiredItem) => {
        bomItem.scheduleChunkUids.forEach((chunkUid: string) => {
          chunkUidNeedToRemove.push(chunkUid);
        });
      });
      console.log("chunkUidNeedToRemove");
      console.log(chunkUidNeedToRemove);
      console.log("targetFirstOrderRequirementData");
      console.log(targetFirstOrderRequirementData);
      let copiedFirstOrderRequirementData: bakeScheduleChunk[] = [];
      copiedFirstOrderRequirementData = targetFirstOrderRequirementData.filter(
        (item: bakeScheduleChunk) => !chunkUidNeedToRemove.includes(item.uid)
      );
      return copiedFirstOrderRequirementData;
    };
    const isEditChunksModalOpen = ref(false);
    const cuEditChunksData: any = ref({
      product: null,
      bomRequiredItem: null,
      chunks: null,
    });
    const onEditBomChunks = (bomRequiredItemUid: string) => {
      isEditChunksModalOpen.value = true;
      // 從所有的排程中找到這個 bomRequiredItemUid
      let targetProduct = cuProjAllRequirementData.value.find((item: any) =>
        item.bom.some((bomItem: any) => bomItem.uid === bomRequiredItemUid)
      );
      if (!targetProduct) {
        message.error("onEditBomChunks 無法找到對應的排程");
        return;
      }

      // 從 targetBomRequiredItem 中找到這個 bomRequiredItemUid
      let targetBomItem = targetProduct.bom.find(
        (item: any) => item.uid === bomRequiredItemUid
      );
      if (!targetBomItem) {
        message.error(
          "onEditBomChunks 無法找到對應的 bomRequiredItemUid 半成品"
        );
        return;
      }

      // 找到這個 bomRequiredItemUid 的所有 chunk
      let targetChunks = cuFirstOrderRequirementData.value.filter((item: any) =>
        targetBomItem.scheduleChunkUids.includes(item.uid)
      );

      // 這邊要開啟一個 modal，讓使用者可以編輯這個 bomRequiredItemUid 的所有 chunk
      console.log(targetChunks);
      cuEditChunksData.value = {
        product: JSON.parse(JSON.stringify(targetProduct)),
        bomRequiredItem: JSON.parse(JSON.stringify(targetBomItem)),
        chunks: JSON.parse(JSON.stringify(targetChunks)),
      };
    };
    const onAddNewChunk = () => {
      // 使用者按下新增 chunk
      // 新增一個 chunk 到 cuEditChunksData
      let maxOrderOnTheDay = findMaxOrderOnTheDay(
        cuEditChunksData.value.chunks[0].chunkDate,
        cuFirstOrderRequirementData.value,
        true
      );
      // newOrderOnTheDay  = maxOrderOnTheDay + 隨機 1-10000 的數字
      let newOrderOnTheDay =
        maxOrderOnTheDay + Math.floor(Math.random() * 10000);

      // 計算還沒排程的量
      let remainingAmount =
        cuEditChunksData.value.bomRequiredItem.materialQuantityRequired;
      cuEditChunksData.value.chunks.forEach((item: any) => {
        remainingAmount -= item.quantity * item.quantityType;
      });
      remainingAmount = Math.round(remainingAmount * 1000) / 1000; // 只取到小數第三位
      let newChunk = {
        bomRequiredItemUid: cuEditChunksData.value.bomRequiredItem.uid,
        name: cuEditChunksData.value.bomRequiredItem.materialName,
        uid: Math.random().toString(36).substring(7),
        chunkDate: cuEditChunksData.value.chunks[0].chunkDate,
        orderOnTheDay: newOrderOnTheDay,
        quantity: remainingAmount,
        quantityType: 1,
      };
      cuEditChunksData.value.chunks.push(newChunk);
    };
    const onRemoveChunk = (chunkUid: string) => {
      // 使用者按下刪除 chunk
      // 從 cuEditChunksData 中找到這個 chunk，然後刪除
      cuEditChunksData.value.chunks = cuEditChunksData.value.chunks.filter(
        (item: any) => item.uid !== chunkUid
      );
    };
    const onSaveBomItemChunks = (
      productScheduleUid: string,
      bomRequiredItemUid: string
    ) => {
      // 使用者按下確認編輯烘焙排程
      // 檢查是否所有的 chunk 的數量總和等於半成品的數量
      let totalAmount = cuEditChunksData.value.chunks.reduce(
        (acc: any, cur: any) => acc + cur.quantity * cur.quantityType,
        0
      );
      if (
        !isAmountValid(
          cuEditChunksData.value.bomRequiredItem.materialQuantityRequired,
          totalAmount
        )
      ) {
        notification.error({
          message: "烘焙數量錯誤",
          description: "烘焙數量總和與半成品數量不符",
        });
        return;
      }

      // 檢查是否所有的 chunk 的日期都在 productRequiredDate 之前或當天
      // 先加一天，不要使用 isSameOrBefore
      let allChunksDateBeforeProductRequiredDate =
        cuEditChunksData.value.chunks.every(
          (item: any) =>
            dayjs(item.chunkDate, "YYYY-MM-DD").isBefore(
              dayjs(
                cuEditChunksData.value.product.productRequiredDate,
                "YYYY-MM-DD"
              ).add(1, "day")
            )
          // dayjs(item.chunkDate, "YYYY-MM-DD").isBefore(
          //   dayjs(
          //     cuEditChunksData.value.product.productRequiredDate,
          //     "YYYY-MM-DD"
          //   )
          // )
        );
      if (!allChunksDateBeforeProductRequiredDate) {
        notification.error({
          message: "烘焙日期錯誤",
          description: "烘焙日期必須在主產品需求日期之前（或當天）",
        });
        return;
      }

      // 確保有這個排程
      const targetProduct = cuProjAllRequirementData.value.find(
        (item: any) => item.uid === productScheduleUid
      );
      if (!targetProduct) {
        message.error("onSaveBomItemChunks 無法找到對應的排程");
        return;
      }

      // 確保有這個半成品
      const targetBomItem = targetProduct.bom.find(
        (item: any) => item.uid === bomRequiredItemUid
      );
      if (!targetBomItem) {
        message.error(
          "onSaveBomItemChunks 無法找到對應的 bomRequiredItemUid 半成品"
        );
        return;
      }

      // 從 cuFirstOrderRequirementData 中找到 bomRequiredItemUid 的所有 chunk 全部刪除
      cuFirstOrderRequirementData.value =
        cuFirstOrderRequirementData.value.filter(
          (item: any) => item.bomRequiredItemUid !== bomRequiredItemUid
        );
      // 把 scheduleChunkUids 清空
      targetBomItem.scheduleChunkUids = [];

      // 把 cuEditChunksData 中的所有 chunk 加入 cuFirstOrderRequirementData
      cuEditChunksData.value.chunks.forEach((item: any) => {
        cuFirstOrderRequirementData.value.push(item);
      });
      // 把 cuEditChunksData 中的所有 chunkID 加入 cuProjAllRequirementData
      targetBomItem.scheduleChunkUids = cuEditChunksData.value.chunks.map(
        (item: any) => item.uid
      );

      // 關閉 modal
      isEditChunksModalOpen.value = false;
      needUpdateData.value = true;
    };
    const isAmountValid = (requiredAmount: number, totalAmount: number) => {
      let result =
        Math.abs(totalAmount - requiredAmount) / requiredAmount > 0.1;
      return !result;
    };
    // #endregion 烘焙模式

    // #region 統計資料
    const currentMonthStatisticData: any = reactive({
      product: [],
      material: [],
    });

    const reCalculateStatisticalData = () => {
      currentStatMonth.value = cuSelectedDay.value.format("YYYY-MM");

      // 清空統計資料
      currentMonthStatisticData.product = [];
      currentMonthStatisticData.material = [];

      // 計算成品需求
      cuProjAllRequirementData.value.forEach((item: any) => {
        // 先確定這個排程是不是在這個月份
        if (
          dayjs(item.productRequiredDate, "YYYY-MM-DD").format("YYYY-MM") !==
          cuSelectedDay.value.format("YYYY-MM")
        ) {
          return;
        }

        // 從 currentMonthStatisticData.product 中找到這個品號的資料
        // 注意 currentMonthStatisticData.product 是一個陣列 of {品號: "xxx", 需求量: 123}
        // 找到他的 index
        let index = currentMonthStatisticData.product.findIndex(
          (product: any) => product.品號 === item.productId
        );
        if (index === -1) {
          // 如果找不到，就新增
          currentMonthStatisticData.product.push({
            品號: item.productId,
            需求量: item.quantityRequired,
          });
        } else {
          // 如果找到，就累加
          currentMonthStatisticData.product[index].需求量 +=
            item.quantityRequired;
        }
      });
      // 計算原料需求
      currentMonthStatisticData.product.forEach((item: any) => {
        // 從 productData 中找到這個品號的資料
        const targetProduct = dbProductData.value.find(
          (product: any) => product[0] === item.品號
        );
        if (targetProduct === undefined) {
          message.error("無此品號");
          return;
        }
        // 從 bomData 中找到這個品號的 BOM
        const bomOfProduct = dbBomMapping.value[targetProduct[0]];
        if (bomOfProduct === undefined) {
          message.error("無此品號的 BOM");
          return;
        }
        // 遍歷 BOM，計算原料需求
        bomOfProduct.forEach((bomItem: any) => {
          // 這裡的 bomItem 是代表了產品其中一個原料
          // 透過 bomItem[2] 找到這個原料的資料
          const targetMaterial = dbProductData.value.find(
            (material: any) => material[0] === bomItem[2]
          );
          if (targetMaterial === undefined) {
            message.error("reCalculateStatisticalData bomOfProduct 無此原料");
            return;
          }

          // 從 currentMonthStatisticData.material 中找到這個原料的資料
          // 注意 currentMonthStatisticData.material 是一個陣列 of {品號: "xxx", 需求量: 123}
          // 找到他的 index
          let index = currentMonthStatisticData.material.findIndex(
            (material: any) => material.品號 === bomItem[2]
          );
          let bomAmount =
            parseFloat(bomItem[4]) /
            parseFloat(bomItem[5]) /
            parseFloat(bomItem[6]) /
            (1 - parseFloat(bomItem[7]));
          if (index === -1) {
            // 如果找不到，就新增
            currentMonthStatisticData.material.push({
              品號: bomItem[2],
              型態: targetMaterial[3],
              需求量: item.需求量 * bomAmount,
            });
          } else {
            // 如果找到，就累加
            currentMonthStatisticData.material[index].需求量 +=
              item.需求量 * bomAmount;
          }
        });
      });

      // 如果還有半成品，就繼續計算
      while (
        currentMonthStatisticData.material.some(
          (item: any) => item.型態 === "102"
        )
      ) {
        let index = currentMonthStatisticData.material.findIndex(
          (item: any) => item.型態 === "102"
        );
        // 複製一份資料
        let materialCopy = JSON.parse(
          JSON.stringify(currentMonthStatisticData.material[index])
        );
        // 刪除原本的資料
        currentMonthStatisticData.material.splice(index, 1);
        // 找到這個品號的資料
        let targetProduct = dbProductData.value.find(
          (item: any) => item[0] === materialCopy.品號
        );
        if (!targetProduct) {
          message.error("無法找到品號 : " + materialCopy.品號);
          continue;
        }

        // 找到這個品號的 BOM
        let bomOfProduct = dbBomMapping.value[targetProduct[0]];
        let bomListLength = bomOfProduct ? bomOfProduct.length : 0;
        for (let j = 0; j < bomListLength; j++) {
          // 找到這個原料的資料
          let targetMaterial = dbProductData.value.find(
            (item: any) => item[0] === bomOfProduct[j][2]
          );

          if (!targetMaterial) {
            message.error("無法找到原料 : " + bomOfProduct[j][2]);
            continue;
          }
          let bomAmount =
            parseFloat(bomOfProduct[j][4]) /
            parseFloat(bomOfProduct[j][5]) /
            parseFloat(bomOfProduct[j][6]) /
            (1 - parseFloat(bomOfProduct[j][7]));

          // 在 currentMonthStatisticData.material 中找到這個原料的資料
          let targetMaterialIndex =
            currentMonthStatisticData.material.findIndex(
              (item: any) => item.品號 === targetMaterial[0]
            );
          if (targetMaterialIndex >= 0) {
            // 如果找到，就累加
            currentMonthStatisticData.material[targetMaterialIndex].需求量 +=
              materialCopy.需求量 * bomAmount;
          } else {
            // 如果找不到，就新增
            currentMonthStatisticData.material.push({
              品號: targetMaterial[0],
              型態: targetMaterial[3],
              需求量: materialCopy.需求量 * bomAmount,
            });
          }
        }
      }
      console.log("currentMonthStatisticData");
      console.log(currentMonthStatisticData);
    };
    // #endregion 統計資料

    // #region 使用者選擇及加入產品
    const productSelectorRef = ref<InstanceType<typeof ProductSelector> | null>(
      null
    );
    const cuUserSelectedProductId = ref<string>("");
    const cuUserInputQuantity = ref<number>(0);
    const cuUserSelectedLine = ref<string>("101");
    const displayAllProduct = ref(false);
    const onUserSelectProduct = (selectedProductId: string) => {
      // 使用選擇器選擇產品
      cuUserSelectedProductId.value = selectedProductId;
    };
    const onAddRequire = () => {
      // 使用者加入產品
      if (cuUserSelectedProductId.value === "") {
        message.error("請選擇產品");
        return;
      }
      // 從 productData 中找到這個品號的資料
      const targetProduct = dbProductData.value.find(
        (product: any) => product[0] === cuUserSelectedProductId.value
      );
      if (targetProduct === undefined) {
        message.error("無此品號");
        return;
      }
      // if (currentProject.value === null) {
      //   message.error("請選擇專案");
      //   return;
      // }
      // if (!currentSelectedProduct.value.productId) {
      //   message.error("請選擇製成品");
      //   return;
      // }
      if (cuUserInputQuantity.value <= 0) {
        message.error("請輸入數量");
        return;
      }

      // 找到今天排程中最大的 orderOnTheDay
      let todayMaxOrder = findMaxOrderOnTheDay(
        cuSelectedDay.value.format("YYYY-MM-DD"),
        cuFirstOrderRequirementData.value,
        false
      );
      let newOrderOnTheDay =
        Math.floor(Math.random() * 10000) + todayMaxOrder + 1;
      cuSelectedDaySchedules.value.push({
        uid: Math.random().toString(36).substring(7),
        productId: targetProduct[0],
        productName: targetProduct[1],
        productSpec: targetProduct[2],
        productAlias: "",
        productionLine: cuUserSelectedLine.value,
        productRequiredDate: cuSelectedDay.value.format("YYYY-MM-DD"),
        quantityRequired: cuUserInputQuantity.value,
        orderOnTheDay: newOrderOnTheDay,
        //bom: dbBomMapping.value[targetProduct[0]], // 這邊不確定修改是否有問題 2024/08/30
        bom: [],
      });
      //console.log(cuProjAllRequirementData);

      // 清空使用者輸入
      cuUserSelectedProductId.value = "";
      cuUserInputQuantity.value = 0;
      productSelectorRef.value?.handleResetComponent();
    };
    // #endregion 使用者選擇及加入產品

    // #region 輸出報表
    const onPrintReport = () => {
      reCalculateStatisticalData();

      let currentDayjsObject = dayjs(cuSelectedDay.value);
      // render a html calendar
      let html = "";
      html += `
        <html>
        <head>
          <title> 
            ${currentDayjsObject.format("YYYY-MM")}
            月排程表
          </title>
          <style>
            table {
              width: 100%;
              border-collapse: collapse;
            }
            tr {
              display: flex;
            }
            tr.data-row {
              display: flex;
              min-height: 30px;
            }
            th {
              flex: 1;
              background-color: #f2f2f2;
              border: 1px solid #dddddd;
              text-align: center;
            }
            td {
              flex: 1;
              border: 1px solid #dddddd;
              text-align: center;
            }
            .date-cell {
              background-color: #e3eefd;
            }
            .data-cell > div {
              margin-top: 2px;
            }
            .out-of-range {
              background-color: #f2f2f2;
            }
            h2 {
              text-align: center;
            }
            body{
              -webkit-print-color-adjust:exact !important;
              print-color-adjust:exact !important;
            }
          </style>
          </head>
      `;

      html += "<body>";
      html += "<div>";

      html += `<h2>${currentDayjsObject.format("YYYY-MM")}月排程表</h2>`;

      // 成品總計，統計該月份的成品需求
      html += `<h3>成品總計</h3>`;
      html += "<table>";
      html += "<tr>";
      html += "<th>品名</th>";
      html += "<th>規格</th>";
      html += "<th>數量</th>";
      html += "</tr>";
      for (let i = 0; i < currentMonthStatisticData.product.length; i++) {
        let targetProduct = dbProductData.value.find(
          (item: any) => item[0] === currentMonthStatisticData.product[i].品號
        );
        html += `<tr>`;
        html += `<td>${targetProduct[1]}</td>`;
        html += `<td>${targetProduct[2]}</td>`;
        html += `<td>${currentMonthStatisticData.product[i].需求量}</td>`;
        html += `</tr>`;
      }
      html += "</table>";

      // 材料總計，統計該月份的最初階材料需求
      html += `<h3>原料總計</h3>`;
      html += "<table>";
      html += "<tr>";
      html += "<th>品名</th>";
      html += "<th>規格</th>";
      html += "<th>數量</th>";
      html += "</tr>";
      for (let i = 0; i < currentMonthStatisticData.material.length; i++) {
        let targetProduct = dbProductData.value.find(
          (item: any) => item[0] === currentMonthStatisticData.material[i].品號
        );
        html += `<tr>`;
        html += `<td>${targetProduct[1]}</td>`;
        html += `<td>${targetProduct[2]}</td>`;
        html += `<td>${currentMonthStatisticData.material[i].需求量.toFixed(
          2
        )}</td>`;
        html += `</tr>`;
      }
      html += "</table>";

      // 成品行事曆
      const daysInMonth = currentDayjsObject.daysInMonth();
      const firstDayOfMonth = currentDayjsObject.date(1).day();
      const weekDays = ["日", "一", "二", "三", "四", "五", "六"];
      html += `<h3>包裝行事曆</h3>`;
      // 線別顏色對照表
      html += "<table>";
      html += "<tr>";
      for (let key in productLineDataMapping) {
        html += `<td style="background-color: ${productLineDataMapping[key].color}">${productLineDataMapping[key].name}</td>`;
      }
      html += "</tr>";
      html += "</table>";

      html += "<table style='margin-top:5px'>";
      html += "<tr>";
      weekDays.forEach((day: any) => {
        html += `<th>${day}</th>`;
      });
      html += "</tr>";

      const emptyCells = firstDayOfMonth;
      let dayCounter = 1;
      // 第一列，日期
      html += "<tr>";
      for (let i = 0; i < emptyCells; i++) {
        html += `<td class="out-of-range"></td>`;
      }
      for (let i = emptyCells; i < 7; i++) {
        html += `<td class="date-cell">${dayCounter}</td>`;
        dayCounter++;
      }
      // 第二列，空白
      dayCounter = 1;
      html += `</tr>`;
      html += `<tr class="data-row">`;
      for (let i = 0; i < emptyCells; i++) {
        html += `<td class="data-cell out-of-range"></td>`;
      }
      for (let i = emptyCells; i < 7; i++) {
        // 這裡要寫入當天的排程
        let currentDayDayjsObject = currentDayjsObject.date(dayCounter);
        html +=
          `<td class="data-cell" >` +
          cuProjAllRequirementData.value
            .filter(
              (item: productRequiredItem) =>
                item.productRequiredDate ===
                currentDayDayjsObject.format("YYYY-MM-DD")
            )
            .map((item: productRequiredItem) => {
              return `<div style="background-color: ${
                productLineDataMapping[item.productionLine].color
              }">
                ${
                  item.productAlias == "" ? item.productName : item.productAlias
                }
                x ${item.quantityRequired}
              </div>`;
            })
            .join("") +
          `</td>`;
        dayCounter++;
      }

      while (dayCounter <= daysInMonth) {
        let dayCounterBeforeRender = dayCounter;
        // 完整的一周，第一列，日期
        html += "<tr>";
        for (let i = 0; i < 7; i++) {
          html +=
            dayCounter <= daysInMonth
              ? `<td class="date-cell">${dayCounter}</td>`
              : `<td class="out-of-range"></td>`;
          dayCounter++;
        }
        // 第二列，空白
        html += `</tr>`;
        html += `<tr class="data-row">`;
        dayCounter = dayCounterBeforeRender;
        for (let i = 0; i < 7; i++) {
          let currentDayDayjsObject = currentDayjsObject.date(dayCounter);
          html +=
            dayCounter <= daysInMonth
              ? `<td class="data-cell" >` +
                cuProjAllRequirementData.value
                  .filter(
                    (item: productRequiredItem) =>
                      item.productRequiredDate ===
                      currentDayDayjsObject.format("YYYY-MM-DD")
                  )
                  .map((item: productRequiredItem) => {
                    return `<div style="background-color: ${
                      productLineDataMapping[item.productionLine].color
                    }">
                      ${
                        item.productAlias == ""
                          ? item.productName
                          : item.productAlias
                      }
                      x ${item.quantityRequired}
                    </div>`;
                  })
                  .join("") +
                `</td>`
              : `<td class="data-cell out-of-range"></td>`;
          dayCounter++;
        }
        html += "</tr>";
      }

      html += "</table>";

      // 烘焙行事曆
      html += `<h3>烘焙排程行事曆</h3>`;
      // 線別顏色對照表
      html += "<table style='margin-top:5px'>";
      html += "<tr>";
      weekDays.forEach((day: any) => {
        html += `<th>${day}</th>`;
      });
      html += "</tr>";

      dayCounter = 1;
      // 第一列，日期
      html += "<tr>";
      for (let i = 0; i < emptyCells; i++) {
        html += `<td class="out-of-range"></td>`;
      }
      for (let i = emptyCells; i < 7; i++) {
        html += `<td class="date-cell">${dayCounter}</td>`;
        dayCounter++;
      }
      // 第二列，空白
      dayCounter = 1;
      html += `</tr>`;
      html += `<tr class="data-row">`;
      for (let i = 0; i < emptyCells; i++) {
        html += `<td class="data-cell out-of-range"></td>`;
      }
      for (let i = emptyCells; i < 7; i++) {
        // 這裡要寫入當天的排程
        let currentDayDayjsObject = currentDayjsObject.date(dayCounter);
        html +=
          `<td class="data-cell" >` +
          cuFirstOrderRequirementData.value
            .filter(
              (item: bakeScheduleChunk) =>
                item.chunkDate === currentDayDayjsObject.format("YYYY-MM-DD")
            )
            .map((item: bakeScheduleChunk) => {
              return `<div style="background-color: #a5cbeb">
                ${item.name} x ${item.quantity} ${
                bakeChunkQuantityTypes.value.find(
                  (type: any) => type.value === item.quantityType
                )?.label
              }
              </div>`;
            })
            .join("") +
          `</td>`;
        dayCounter++;
      }

      while (dayCounter <= daysInMonth) {
        let dayCounterBeforeRender = dayCounter;
        // 完整的一周，第一列，日期
        html += "<tr>";
        for (let i = 0; i < 7; i++) {
          html +=
            dayCounter <= daysInMonth
              ? `<td class="date-cell">${dayCounter}</td>`
              : `<td class="out-of-range"></td>`;
          dayCounter++;
        }
        // 第二列，空白
        html += `</tr>`;
        html += `<tr class="data-row">`;
        dayCounter = dayCounterBeforeRender;
        for (let i = 0; i < 7; i++) {
          let currentDayDayjsObject = currentDayjsObject.date(dayCounter);
          html +=
            dayCounter <= daysInMonth
              ? `<td class="data-cell" >` +
                cuFirstOrderRequirementData.value
                  .filter(
                    (item: bakeScheduleChunk) =>
                      item.chunkDate ===
                      currentDayDayjsObject.format("YYYY-MM-DD")
                  )
                  .map((item: bakeScheduleChunk) => {
                    return `<div style="background-color: #a5cbeb">
                      ${item.name} x ${item.quantity} ${
                      bakeChunkQuantityTypes.value.find(
                        (type: any) => type.value === item.quantityType
                      )?.label
                    }
                    </div>`;
                  })
                  .join("") +
                `</td>`
              : `<td class="data-cell out-of-range"></td>`;
          dayCounter++;
        }
        html += "</tr>";
      }

      html += "</table>";

      // end of html
      html += "</div>";
      html += "</body></html>";
      // open a new window and write the html
      const anchor = document.createElement("a");
      anchor.href = "data:text/html;charset=utf-8," + encodeURIComponent(html);
      anchor.target = "_blank";
      anchor.download = `${dayjs(cuSelectedDay.value).format(
        "YYYY-MM"
      )}月排程表.html`;
      anchor.click();
      // remove anchor
      setTimeout(() => {
        anchor.remove();
      }, 1000);
    };
    // #endregion 輸出報表
    return {
      // lib //
      dayjs,
      locale,
      // data //
      isLoadingDataFromDb,
      dbProductData,
      dbBomMapping,
      // static //
      productLineDataMapping,
      // project //
      cuProjAllRequirementData,
      cuUserSelectedLine,
      cuSelectedDay,
      onUploadData,
      needUpdateData,
      // 單日點選相關 //
      isEditScheduleModalOpen,
      cuUserInputQuantity,
      cuSelectedDaySchedules,
      onEditOneDaySchedule,
      onUserSelectProduct,
      onAddRequire,
      onConfirmEditSchedule,
      onRemoveSchedule,
      productSelectorRef,
      displayAllProduct,
      // 編輯排程屬性相關 //
      isEditSchedulePropertyModalOpen,
      currentChangePropertySchedule,
      onEditScheduleProperty,
      onSaveProductProperty,
      // 烘焙模式相關 //
      isScheduleMode,
      onEditBomChunks,
      isEditChunksModalOpen,
      cuEditChunksData,
      onSaveBomItemChunks,
      onRemoveChunk,
      onAddNewChunk,
      bakeChunkQuantityTypes,
      isAmountValid,
      currentScreenBakeryProdcutColorMapping,
      currentMainProductColorMapping,
      toggleGhostOfMainProductColor,
      // 日曆相關 //
      getScheduleByDate,
      onChangeCalendarSelectedDay,
      startDragEvent,
      ghostEvent,
      // 日曆內容高度、寬度相關 //
      calendarContentHeight,
      calendarContentWidth,
      // 報表相關 //
      onPrintReport,
    };
  },
});
