
import { defineComponent, onMounted, ref, computed } from "vue";
import { useRoute } from "vue-router";
import { message } from "ant-design-vue";
import {
  fetchMachineHistoryById,
  fetchMachineInfoById,
} from "@/api/machine-history-detail";

interface TimelineEvent {
  事件: string;
  日期: string;
  備註: string;
  客戶名稱?: string;
  tagtype: "info" | "default" | "warning" | "success";
  杯數?: string;
  咖啡清洗?: string;
  牛奶清洗?: string;
}

interface MachineInfo {
  類型: string;
  品號: string;
  品名: string;
  取得日期: string;
  最後異動狀態: string;
  放置客戶代號: string;
  放置客戶名稱: string;
}

const changeTypeMapping: Record<string, string> = {
  1: "入庫",
  2: "銷貨",
  3: "領用",
  4: "轉撥",
  5: "調整",
  6: "維修",
  7: "出貨通知",
  8: "製令",
  0: "期初導入",
  R: "註冊序號",
};

const repairsheetTypeMapping: Record<string, string> = {
  A2: "維修",
  C1: "維修",
  C2: "保養",
  C3: "其它",
  C4: "整機",
  C5: "保固",
  C6: "裝機",
  C7: "試機",
  C8: "移機",
  C9: "撤機",
};

export default defineComponent({
  name: "MachineHistoryRwd",
  props: {
    defaultMachineId: {
      type: String,
      default: "",
    },
  },
  setup(props) {
    const route = useRoute();
    const machineId = ref(
      (route.query.machineId as string) || props.defaultMachineId || ""
    );
    const loading = ref(false);
    const hasQueried = ref(false);
    const timelineData = ref<TimelineEvent[]>([]);
    const machineInfo = ref<MachineInfo | null>(null);

    const infoUpdatedAt = computed(() => {
      if (!machineInfo.value) return "-";
      const now = new Date();
      const hour = now.getHours().toString().padStart(2, "0");
      const minute = now.getMinutes().toString().padStart(2, "0");
      return `${now.getMonth() + 1}/${now.getDate()} ${hour}:${minute}`;
    });

    const getColorByTag = (tag: string) => {
      switch (tag) {
        case "info":
          return "blue";
        case "warning":
          return "orange";
        case "success":
          return "green";
        default:
          return "gray";
      }
    };

    const formatDate = (val: string) => {
      const str = val.toString();
      if (str.length < 8) return str;
      return `${str.substring(0, 4)}-${str.substring(4, 6)}-${str.substring(
        6,
        8
      )}`;
    };

    const buildTimeline = (raw: any[]) => {
      const mapped: TimelineEvent[] = [];
      raw.forEach((element: any) => {
        const dateString = formatDate(element[0]);
        if (element[6] === "REPAIR") {
          mapped.push({
            事件: repairsheetTypeMapping[element[1]] || "維修",
            日期: dateString,
            備註:
              element[2]
                ?.toString()
                .replace(/<咖啡清洗:\d+>|<牛奶清洗:\d+>/g, "") || "",
            客戶名稱: element[4],
            杯數: element[5],
            咖啡清洗: element[2]?.match(/<咖啡清洗:(\d+)>/)?.[1] || "",
            牛奶清洗: element[2]?.match(/<牛奶清洗:(\d+)>/)?.[1] || "",
            tagtype:
              repairsheetTypeMapping[element[1]] === "保養"
                ? "info"
                : "default",
          });
        } else {
          mapped.push({
            事件: "異動-" + (changeTypeMapping[element[1]] || element[1]),
            日期: dateString,
            備註: element[3],
            tagtype: "warning",
          });
        }
      });
      timelineData.value = mapped;
    };

    const handleSearch = async () => {
      const inputId = machineId.value.trim();
      if (!inputId) {
        message.warning("請先輸入機器序號");
        return;
      }
      loading.value = true;
      hasQueried.value = true;
      try {
        const [history, info] = await Promise.all([
          fetchMachineHistoryById(inputId),
          fetchMachineInfoById(inputId),
        ]);
        buildTimeline(history || []);
        machineInfo.value = info || null;
        if ((history || []).length === 0) {
          message.info("查無歷程資料");
        }
      } catch (err) {
        message.error("取得機器歷程失敗，請稍後再試");
        timelineData.value = [];
        machineInfo.value = null;
        console.log("query history error", err);
      } finally {
        loading.value = false;
      }
    };

    onMounted(() => {
      if (machineId.value) {
        handleSearch();
      }
    });

    return {
      machineId,
      loading,
      hasQueried,
      timelineData,
      machineInfo,
      handleSearch,
      getColorByTag,
      infoUpdatedAt,
    };
  },
});
