// Central transport layer for talking to the GAS backend.
//
// GAS Web Apps cannot handle CORS preflight (OPTIONS) requests or set custom
// response headers, so every request here is a "simple request" per the
// Fetch/CORS spec: POST with Content-Type: text/plain (never
// application/json) and no custom headers. The auth token therefore travels
// inside the JSON body, not an Authorization header. GAS also can't set a
// custom HTTP status code on its response, so auth/business failures are
// signaled via a body-level `ok:false` flag rather than an HTTP status.
import router from "@/router";
import auth from "@/store/auth";

const API_BASE_URL = process.env.VUE_APP_GAS_API_URL;

interface ApiSuccess<T> {
  ok: true;
  data: T;
}
interface ApiError {
  ok: false;
  error: { code: string; message: string };
}

export function callApi<T = any>(
  action: string,
  payload: Record<string, any> = {},
  { skipAuth = false }: { skipAuth?: boolean } = {}
): Promise<T> {
  if (!API_BASE_URL) {
    // vue-cli-service serve (dev mode) does NOT load .env.production --
    // only .env / .env.local / .env.development / .env.development.local.
    // Without VUE_APP_GAS_API_URL set, fetch() would silently hit a
    // same-origin relative path and fail in a confusing way.
    throw new Error(
      "VUE_APP_GAS_API_URL 未設定，請建立 .env.local 並指向已部署的 GAS /exec URL（見 README）"
    );
  }

  const body: Record<string, any> = { action, payload };
  if (!skipAuth) {
    body.token = auth.token;
  }

  return fetch(API_BASE_URL, {
    method: "POST",
    headers: { "Content-Type": "text/plain;charset=utf-8" },
    body: JSON.stringify(body),
  })
    .catch(() => {
      throw new Error("網路連線失敗，請稍後再試");
    })
    .then((res) =>
      res.json().catch(() => {
        throw new Error(
          "伺服器回應格式錯誤（非 JSON），請確認 API URL 是否正確"
        );
      })
    )
    .then((json: ApiSuccess<T> | ApiError) => {
      if (!json.ok) {
        const code = json.error && json.error.code;
        const message = (json.error && json.error.message) || "發生未知錯誤";
        if (code === "UNAUTHORIZED" && !skipAuth) {
          auth.logout();
          router.push({
            name: "login",
            query: { redirect: router.currentRoute.value.fullPath },
          });
        }
        throw new Error(message);
      }
      return json.data;
    });
}

export function login(password: string) {
  return callApi<{
    token: string;
    userUnifiedID: string;
    userName: string;
    userRole: string[];
  }>("login", { password }, { skipAuth: true }).then((data) => {
    auth.setSession(
      data.token,
      data.userUnifiedID,
      data.userName,
      data.userRole
    );
    return data;
  });
}
