];

const locationOptions = [
  { label: "北中南", value: "北中南" },
  { label: "桃竹東", value: "桃竹東" },
];

const machineProblemPhraseList = [
  "冰箱溫昇",
  "不加熱",
  "漏水",
  "只出牛奶不出咖啡",
  "口味不對",
  "異聲",
  "牛奶溫度不足",
  "螢幕不動作(當機)",
  "不動作(當機)",
  "水盤排水堵塞",
  "咖啡溫度過高",
  "牛奶量不足",
  "不出牛奶",
  "牛奶結冰(冰箱溫度低)",
  "不出蒸氣",
  "漏電",
  "跳電",
  "不出熱水",
  "溫度計故障",
  "出料太慢",
  "訂購零件藥水",
  "蒸氣管路脫落",
