// #endregion staticData

export default defineComponent({
  name: "CallCenterMainViewer",
  components: {
    ATable: Table,
    AUserOutlined: UserOutlined,
    AFileOutlined: FileOutlined,
    APlusOutlined: PlusOutlined,
    AInboxOutlined: InboxOutlined,
    AFiledTimeOutLined: FieldTimeOutlined,
    ARedoOutlined: RedoOutlined,
    ADeleteOutlined: DeleteOutlined,
  },
  setup() {
    // #region New-case-Edit-Case-Related

    const newCaseData: any = ref({});
    const newCaseModalVisible = ref<boolean>(false);
    const newCaseModalconfirmLoading = ref<boolean>(false);
    const currentModalType = ref<string>("新增");
    const currentMachineData = ref<any>({});
    const searchMachineSerialNumberLoading = ref<boolean>(false);
    const userPhraseSearchValue = ref<string>("");

    const handleCreateNewCase = () => {
      // 送出更新或新增的資料
      newCaseModalconfirmLoading.value = true;

      if (!newCaseData.value.rowNum) {
        // 新增案件的話，要初始化一些資料

        if (!newCaseData.value.預排時間) {
          if (newCaseData.value.tag.includes("緊急叫修")) {
            // 如果是緊急叫修的案件，則由主管派工，但目前傳到群組所以使用自行領案
            // newCaseData.value.status = "尚未派工";
            newCaseData.value.status = "已通知未領案";
          } else {
            newCaseData.value.status = "已通知未領案";
          }
        } else {
          // 如果有預排時間，則狀態為預排尚未通知
          newCaseData.value.status = "預排尚未通知";
        }
        newCaseData.value.rowNum = -1;
        newCaseData.value.assignedEngineer = [];
      }
      // 新增更新、創建者資訊
      newCaseData.value.history.push({
        updateTimestamp: dayjs().valueOf(),
        updaterID: auth.userUnifiedID,
        動作: `${currentModalType.value}案件`,
        備註: "",
      });
      // 送出到後端
      addOrEditCase(newCaseData.value, (returnObj: any) => {
        // reloadData(); // 這邊應該要避免重複讀取資料
        if (currentModalType.value === "新增") {
          startLineNotifyCountdown();
          dbData.rawData.push(returnObj);
        } else {
          // 編輯的話，要找到原本的資料，並且替換掉
          let findIndex = dbData.rawData.findIndex(
            (record: any) => record.timestamp === returnObj.timestamp
          );
          if (findIndex >= 0) {
            dbData.rawData[findIndex] = JSON.parse(JSON.stringify(returnObj));
          }
        }
        //dbData.rawData.push(returnObj);
        onChangeAnyFilter();
        newCaseModalVisible.value = false;
        newCaseModalconfirmLoading.value = false;
        message.success("新增成功");
      });
    };
    const openNewCaseModal = (timestamp: number) => {
      // 要清空機器資訊
      currentMachineData.value = {};

      if (timestamp > 0) {
        // 是一個已經存在的案件，要先找到資料
        let findData = dbData.rawData.find(
          (record: any) => record.timestamp === timestamp
        );
        if (findData) {
          newCaseData.value = JSON.parse(JSON.stringify(findData));
          currentModalType.value = "編輯";
          // 帶入已經上傳的檔案
          let fileIndex = 0;
          temporarilyUploadedFiles.value = newCaseData.value.files.map(
            (fileId: string) => {
              return {
                uid: fileId,
                name: newCaseData.value.timestamp + "-" + fileIndex++,
                status: "done",
                response: fileId,
                url: `https://drive.google.com/file/d/${fileId}/preview`,
              };
            }
          );
        } else {
          message.error("找不到資料");
          return;
        }
      } else {
        // 是一個新的案件，要初始化資料
        currentModalType.value = "新增";
        newCaseData.value = {};
        newCaseData.value.timestamp = dayjs().valueOf();
        newCaseData.value.customerID = "";
        newCaseData.value.customerName = "";
        newCaseData.value.machineProblem = "";
        newCaseData.value.customerAddress = "";
        newCaseData.value.customerContact = "";
        newCaseData.value.customerPhone = "";
        // newCaseData.value.caseBuilder = props.userUnifiedID;
        newCaseData.value.assignedEngineer = "";
        newCaseData.value.status = "";
        newCaseData.value.files = [];
        newCaseData.value.history = [];
        newCaseData.value.tag = [];
        newCaseData.value.location = "北中南";
        newCaseData.value.needNotify = true;
        newCaseData.value.machineList = [];
        // 要清空暫存的檔案
        temporarilyUploadedFiles.value = [];
      }
      // open modal
      newCaseModalVisible.value = true;
    };
    const onSearchMachineSerialNumber = () => {
      searchMachineSerialNumberLoading.value = true;
      fetchMachineInformation(
        currentMachineData.value.machineSerialNumber,
        (data: any) => {
          currentMachineData.value.machineSpec = data.品名;
          currentMachineData.value.machineIdType = data.類型;
          currentMachineData.value.machineLastUpdateType = data.最後異動狀態;
          console.log(data); // 顯示的機器資訊，不存到資料庫
          if (data.取得日期 != "無資料") {
            let dayJsObject = dayjs(data.取得日期, "YYYYMMDD");
            currentMachineData.value.machineGetDate =
              dayJsObject.format("YYYY-MM-DD");
            currentMachineData.value.hasExpired = dayJsObject
              .add(365, "days")
              .isBefore(dayjs());
          } else {
            currentMachineData.value.machineGetDate = "";
          }

          searchMachineSerialNumberLoading.value = false;
        }
      );
    };
    const onAddMachineToNewCase = () => {
      if (currentMachineData.value.machineSerialNumber) {
        newCaseData.value.machineList.push({
          machineSerialNumber: currentMachineData.value.machineSerialNumber,
          machineSpec: currentMachineData.value.machineSpec,
        });
        currentMachineData.value = {};
      }
    };
    const onDeleteMachineFromNewCase = (index: number) => {
      newCaseData.value.machineList.splice(index, 1);
    };
    const customerAutoCompleteOptions = ref<any[]>([]);
    const onSearchCustomer = (searchValue: string) => {
      customerAutoCompleteOptions.value = !searchValue
        ? []
        : dbData.customerTable
            .filter((customer: any) => {
              return (
                customer.客戶名稱.includes(searchValue) ||
                customer.客戶代號.includes(searchValue)
              );
            })
            .map((customer: any) => {
              return {
                query: searchValue,
                value: customer.客戶代號,
                customerName: customer.客戶名稱,
              };
            });
    };
    const onSelectCustomer = (userSelectedCustomerID: string) => {
      const selectedCustomer = dbData.customerTable.find(
        (customer: any) => customer.客戶代號 === userSelectedCustomerID
      );
      newCaseData.value.customerID = selectedCustomer.客戶代號;
      newCaseData.value.customerName = selectedCustomer.客戶名稱;
    };
    const highlightText = (text: string, query: string) => {
      if (!query) {
        return text;
      }
      const regex = new RegExp(`(${query})`, "gi");
      return text.replace(regex, '<span style="color: #ff5500">$1</span>');
    };

    const getCustomerDataLoading = ref<boolean>(false);
    const customerData = ref<any>({});
    const getCustomerDataById = () => {
      if (!newCaseData.value.customerID) {
        message.error("請先選擇客戶");
        return;
      }
      if (
        customerData.value.customerData &&
        customerData.value.customerData.客戶代號 == newCaseData.value.customerID
      ) {
        // 如果已經有資料了，就不用再重新取得
        return;
      }
      getCustomerDataLoading.value = true;
      // 清空原本的資料
      customerData.value = {};
      getCustomerContactAndMachine(
        newCaseData.value.customerID,
        (data: any) => {
          console.log(newCaseData.value.customerID);
          console.log(JSON.stringify(data, null, 2));
          getCustomerDataLoading.value = false;
          customerData.value = data;
        }
      );
    };
    const onAddCustomerMachine = (index: number) => {
      newCaseData.value.machineList.push({
        machineSerialNumber: customerData.value.machineData[index].機器代號,
        machineSpec: customerData.value.machineData[index].機器規格,
      });
    };
    const temporarilyUploadedFiles = ref([]);
    const handleFileChange = (info: UploadChangeParam) => {
      /* example of info object
      {
        // current update file
        "file": {
            "uid": "vc-upload-1698403136520-3",
            "lastModified": 1698400912700,
            "lastModifiedDate": "2023-10-27T10:01:52.700Z",
            "name": "1697617737001_03.mp4",
            "size": 5200097,
            "type": "video/mp4",
            "percent": 100,
            "originFileObj": {
                "uid": "vc-upload-1698403136520-3"
            },
            "status": "done",
            "response": "1pAp72r6Tk1dWwtupiY-rREjdX17dXjUy"
        },
        // all uploaded files
        "fileList": [
            {
                "uid": "vc-upload-1698403136520-3",
                "lastModified": 1698400912700,
                "lastModifiedDate": "2023-10-27T10:01:52.700Z",
                "name": "1697617737001_03.mp4",
                "size": 5200097,
                "type": "video/mp4",
                "percent": 100,
                "originFileObj": {
                    "uid": "vc-upload-1698403136520-3"
                },
                "status": "done",
                "response": "1pAp72r6Tk1dWwtupiY-rREjdX17dXjUy"
            }
        ]
      }
      */
      console.log("handleFileChange");
      console.log(info);

      if (info.file.status === "removed") {
        // remove file from google drive
        removeFileByID(info.file.response, () => {
          console.log("removeFileByID");
          console.log(info.file.response);
          // remove file from newCaseData
          newCaseData.value.files = newCaseData.value.files.filter(
            (fileId: string) => fileId !== info.file.response
          );
        });
        return;
      } else if (info.file.status === "error") {
        message.error("上傳失敗");
        return;
      } else if (info.file.status === "uploading") {
        return;
      } else if (info.file.status === "done") {
        message.success("上傳成功");
      }

      // 把 info.fileList 中的 response (google drive 的 file id)
      // 放到 newCaseData.value.files 中
      newCaseData.value.files = info.fileList.map((file) => file.response);
      // 從 temporarilyUploadedFiles 中找到 info

      let findFile: any = temporarilyUploadedFiles.value.find((file: any) => {
        return file.uid === info.file.uid;
      });

      // 把 temporarilyUploadedFiles 中的 url 改成 google drive 的 url
      if (findFile) {
        findFile.url = `https://drive.google.com/file/d/${info.file.response}/preview`;
      }
      console.log(newCaseData.value.files);
    };
    const handleFileUpload = async (info: any) => {
      const { file } = info;
      // get base64 string from file
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64FileString = reader.result;
        uploadFileToGoogleDrive(
          newCaseData.value.timestamp,
          base64FileString,
          (returnFileID: any) => {
            // console.log("handleFileUploadToGoogleDrive");
            // console.log(returnFileID);
            info.onSuccess(returnFileID);
          },
          (error: any) => {
            // console.log("handleFileUploadToGoogleDrive");
            console.log(error);
            info.onError(error);
          }
        );
      };
    };

    // #endregion New-case-Edit-Case-Related

    // #region Update-Status-Related
    const caseStatusUpdating = ref<boolean>(false);
    const updateCaseStatusDialogVisible = ref<boolean>(false);
    const formUpdateCaseActionData = ref<any>({
      動作: "",
      備註: "",
      updateTimestamp: 0,
      updaterID: auth.userUnifiedID,
    });
    const currentCaseData = ref<any>({});
    const reinitUpdateCaseForm = (action: string) => {
      formUpdateCaseActionData.value = {};
      formUpdateCaseActionData.value.updateTimestamp = -1;
      formUpdateCaseActionData.value.updaterID = auth.userUnifiedID;
      formUpdateCaseActionData.value.備註 = "";
      formUpdateCaseActionData.value.動作 = action;

      // 指派工程師的話，要把原工程師的資料帶入
      if (action === "主管派工") {
        formUpdateCaseActionData.value.指派人員 =
          currentCaseData.value.assignedEngineer;
      }
    };
    const openUpdateCaseStatusDialog = (caseTimeStamp: number) => {
      updateCaseStatusDialogVisible.value = true;
      reinitUpdateCaseForm("");
      // find current data by caseNumber
      let findData = dbData.rawData.find(
        (data: any) => data.timestamp === caseTimeStamp
      );
      if (findData) {
        currentCaseData.value = findData;
      } else {
        message.error("找不到資料");
        return;
      }
      console.log(currentCaseData.value);
    };
    const onSubmitUpdateCaseAction = () => {
      if (!formUpdateCaseActionData.value.動作) {
        message.error("請選擇動作");
        return;
      }
      caseStatusUpdating.value = true;
      formUpdateCaseActionData.value.updateTimestamp = dayjs().valueOf();
      formUpdateCaseActionData.value.updaterID = auth.userUnifiedID;
      console.log(formUpdateCaseActionData.value);
      updateCaseStatusFromConsole(
        currentCaseData.value.rowNum,
        formUpdateCaseActionData.value,
        (returnObj: any) => {
          caseStatusUpdating.value = false;
          message.success("更新狀態成功");
          updateCaseStatusDialogVisible.value = false;
          // 這邊要更新 dbData.rawData
          // find index in dbData.rawData
          let updateDataIndex = dbData.rawData.findIndex(
            (data: any) => data.timestamp === currentCaseData.value.timestamp
          );
          console.log(updateDataIndex);
          console.log(currentCaseData.value.timestamp);
          if (updateDataIndex >= 0) {
            dbData.rawData[updateDataIndex] = JSON.parse(
              JSON.stringify(returnObj)
            );
          }
          onChangeAnyFilter();
        }
      );
    };

    // #endregion Update-Status-Related

    // #region Main-Data-Fetch-Related
    const userSelectedStatus: any = ref(
      caseStatus.map((status) => status.value)
    );
    // 移除已完修結案的狀態
    userSelectedStatus.value.splice(
      userSelectedStatus.value.indexOf("完修結案"),
      1
    );
    const isLoading: any = ref(false);
    const dbData: any = reactive({
      rawData: null,
      displayData: [],
      customerTable: [],
      engineerMapping: {},
    });
    const previousUpdateTimeString = ref(dayjs().format("MM/DD HH:mm"));

    // #region Init Loading Related
    const initLoadingVisible = ref(false);
    const initLoadingPercent = ref(0);
    const initLoadingStatus = ref<"active" | "exception" | "success">("active");
    const initLoadingErrorMsg = ref("");
    let initLoadingInterval: any = null;

    const startInitLoading = () => {
      initLoadingVisible.value = true;
      initLoadingPercent.value = 0;
      initLoadingStatus.value = "active";
      initLoadingErrorMsg.value = "";
      if (initLoadingInterval) clearInterval(initLoadingInterval);

      initLoadingInterval = setInterval(() => {
        if (initLoadingPercent.value < 90) {
          // 隨機增加 0~5
          const increment = Math.floor(Math.random() * 6);
          initLoadingPercent.value = Math.min(
            90,
            initLoadingPercent.value + increment
          );
        }
      }, 1000);
    };
    // #endregion Init Loading Related

    // #region Countdown Timer Related
    const countdownTimerVisible = ref(false);
    const countdownSeconds = ref(120);
    let countdownInterval: any = null;

    const startLineNotifyCountdown = () => {
      if (countdownInterval) clearInterval(countdownInterval);
      countdownSeconds.value = 120;
      countdownTimerVisible.value = true;

      countdownInterval = setInterval(() => {
        countdownSeconds.value--;
        if (countdownSeconds.value <= 0) {
          clearInterval(countdownInterval);
        }
      }, 1000);
    };

    const formatCountdownTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, "0")}`;
    };

    const closeCountdownTimer = () => {
      countdownTimerVisible.value = false;
      if (countdownInterval) clearInterval(countdownInterval);
    };
    // #endregion Countdown Timer Related

    const userSelectedTag: any = ref(null);
    const userSelectedEngineer: any = ref(null);
    const engineerOptions: any = ref([]);
    const userSelectedLocation: any = ref(null);
    const selectDateStart: any = ref<Dayjs>();
    const selectDateEnd: any = ref<Dayjs>();
    const caseNumberSearchValue: any = ref(null);
    const caseCountMapping: any = ref({});

    onMounted(() => {
      startInitLoading();
      reloadData(
        () => {
          // Success
          initLoadingPercent.value = 100;
          initLoadingStatus.value = "success";
          if (initLoadingInterval) clearInterval(initLoadingInterval);
          setTimeout(() => {
            initLoadingVisible.value = false;
          }, 1000);
        },
        () => {
          // Fail
          initLoadingStatus.value = "exception";
          initLoadingErrorMsg.value = "讀取資料失敗";
          if (initLoadingInterval) clearInterval(initLoadingInterval);
        }
      );
    });
    const reloadData = (onSuccess?: () => void, onError?: () => void) => {
      isLoading.value = true;
      fetchCallCenterData(
        (data: any): void => {
          dbData.customerTable = data.客戶資料;
          dbData.engineerMapping = data.工程師資料;
          // 從 data.工程師資料轉換成 engineerOptions
          engineerOptions.value = Object.entries(data.工程師資料).map(
            ([key, value]) => {
              return {
                label: value,
                value: key,
              };
            }
          );
          // console.log(dbData.rawData);

          let nowDayjsObject = dayjs();
          dbData.rawData = data.叫修案件.map((record: any) => {
            // 複製一份，避免直接修改原本的資料
            let cuRecord = { ...record };
            // 計算應完成時間
            if (cuRecord.tag.includes("緊急叫修")) {
              cuRecord.應完修時間 = dayjs(cuRecord.timestamp).add(1, "days");
            } else {
              cuRecord.應完修時間 = dayjs(cuRecord.timestamp).add(2, "days");
            }
            // 若已完成，看 history 的最後一筆時間
            let completeTime = nowDayjsObject;
            if (cuRecord.status === "完修結案") {
              // 從最後面尋找 history 中第一個不是 "編輯案件" 的動作
              for (let i = cuRecord.history.length - 1; i >= 0; i--) {
                if (cuRecord.history[i].動作 !== "編輯案件") {
                  completeTime = dayjs(cuRecord.history[i].updateTimestamp);
                  break;
                }
              }
            }
            if (cuRecord.應完修時間.isBefore(completeTime)) {
              cuRecord.tag.push("逾時案件");
            }
            return cuRecord;
          });

          isLoading.value = false;
          previousUpdateTimeString.value = dayjs().format("MM/DD HH:mm");
          onChangeAnyFilter();

          if (onSuccess) onSuccess();
        },
        () => {
          isLoading.value = false;
          if (onError) onError();
        }
      );
    };

    const onChangeAnyFilter = () => {
      // 這邊透過轉換 dbData.rawData 來產生 dbData.displayData
      caseCountMapping.value = {};
      dbData.displayData = dbData.rawData.filter((record: any) => {
        // 標記
        if (
          userSelectedTag.value &&
          !record.tag.includes(userSelectedTag.value)
        ) {
          return false;
        }
        // 區域
        if (
          userSelectedLocation.value &&
          record.location !== userSelectedLocation.value
        ) {
          return false;
        }

        // 工程師
        if (
          userSelectedEngineer.value &&
          !record.assignedEngineer.includes(userSelectedEngineer.value)
        ) {
          return false;
        }

        // 日期 篩選 這邊要注意，要把時間轉換成當天的 00:00:00
        if (
          selectDateStart.value &&
          record.timestamp < selectDateStart.value.startOf("day").valueOf()
        ) {
          return false;
        }
        if (
          selectDateEnd.value &&
          record.timestamp > selectDateEnd.value.endOf("day").valueOf()
        ) {
          return false;
        }

        // 案件編號
        if (caseNumberSearchValue.value) {
          let caseNumberStr = dayjs(record.timestamp).format(
            "YYYY-MM-DD-HH-mm-ss-SSS"
          );
          if (caseNumberSearchValue.value.toString() != caseNumberStr) {
            return false;
          }
        }
        // 計算案件數量應該要在篩選狀態之前
        if (!caseCountMapping.value[record.status]) {
          caseCountMapping.value[record.status] = 1;
        } else {
          caseCountMapping.value[record.status]++;
        }

        // 狀態
        if (!userSelectedStatus.value.includes(record.status)) {
          return false;
        }
        return true;
      });
    };

    // #endregion Main-Data-Fetch-Related

    // #region Auto-Reload-Related
    const AUTO_RELOAD_INTERVAL = 60 * 10;
    const autoReloadMode = ref(false);
    const autoReloadCountDown = ref(9999);
    const autoReloadPercentage = ref(0);
    let intervalId: any = null;
    let onDayCountDown = 60 * 60 * 24;
    const onSwitchAutoReload = (checked: boolean) => {
      if (checked) {
        autoReloadCountDown.value = AUTO_RELOAD_INTERVAL;
        autoReloadPercentage.value = 0;
        onDayCountDown = 60 * 60 * 24;
        intervalId = setInterval(() => {
          autoReloadCountDown.value--;
          onDayCountDown--;
          autoReloadPercentage.value =
            (1 - autoReloadCountDown.value / AUTO_RELOAD_INTERVAL) * 100;
          if (autoReloadCountDown.value <= 0) {
            reloadData();
            autoReloadCountDown.value = AUTO_RELOAD_INTERVAL;
            autoReloadPercentage.value = 0;
          }
          if (onDayCountDown <= 0) {
            clearInterval(intervalId);
          }
        }, 1000);
      } else {
        if (intervalId) {
          clearInterval(intervalId);
        }
      }
    };

    // #endregion Auto-Reload-Related

    // #region Utils-function
    const sortHistory = (history: any) => {
      return history
        .slice()
        .sort((a: any, b: any) => b.updateTimestamp - a.updateTimestamp);
    };

    const downloadingSignPdf = ref("");
    const downloadSignPdf = (signSheetId: string) => {
      downloadingSignPdf.value = signSheetId;
      let filename = "卡塔摩納維修單-" + signSheetId + ".pdf";
      fetchPdfLinkByFilename(filename, (url: string) => {
        window.open(url);
        downloadingSignPdf.value = "";
      });
    };
    // #endregion Utils-function

    return {
      /* package */
      dayjs,
      locale,
      /* static data */
      caseStatus,
      caseColumns,
      caseTags,
      locationOptions,
      /* main data */
      dbData,
      isLoading,
      sortHistory,
      reloadData,
      autoReloadMode,
      onSwitchAutoReload,
      autoReloadCountDown,
      autoReloadPercentage,
      /* Filter related */
      onChangeAnyFilter,
      userSelectedStatus,
      userSelectedTag,
      userSelectedEngineer,
      userSelectedLocation,
      engineerOptions,
      previousUpdateTimeString,
      selectDateStart,
      selectDateEnd,
      caseNumberSearchValue,
      caseCountMapping,
      /* New case / Edit Case Related */
      newCaseModalVisible,
      newCaseModalconfirmLoading,
      currentModalType,
      handleCreateNewCase,
      openNewCaseModal,
      newCaseData,
      onSearchMachineSerialNumber,
      onAddMachineToNewCase,
      onDeleteMachineFromNewCase,
      customerAutoCompleteOptions,
      onSearchCustomer,
      onSelectCustomer,
      highlightText,
      getCustomerDataById,
      onAddCustomerMachine,
      getCustomerDataLoading,
      customerData,
      handleFileChange,
      handleFileUpload,
      currentMachineData,
      userPhraseSearchValue,
      machineProblemPhraseList,
      // handleFilePreview,
      temporarilyUploadedFiles,
      searchMachineSerialNumberLoading,
      downloadSignPdf,
      downloadingSignPdf,
      /* Update Status Related */
      caseStatusUpdating,
      currentCaseData,
      updateCaseStatusDialogVisible,
      formUpdateCaseActionData,
      reinitUpdateCaseForm,
      openUpdateCaseStatusDialog,
      onSubmitUpdateCaseAction,
      /* Init Loading */
      initLoadingVisible,
      initLoadingPercent,
      initLoadingStatus,
      initLoadingErrorMsg,
      /* Countdown Timer */
      countdownTimerVisible,
      countdownSeconds,
      formatCountdownTime,
      closeCountdownTimer,
    };
  },
});
