
import { Layout, LayoutContent, LayoutSider } from "ant-design-vue";
import {
  UserOutlined,
  MenuOutlined,
  LogoutOutlined,
} from "@ant-design/icons-vue";
import { defineComponent, onUnmounted, ref, computed } from "vue";
import { useRoute, useRouter } from "vue-router";
import auth from "@/store/auth";

export default defineComponent({
  props: [],
  components: {
    Layout,
    LayoutSider,
    LayoutContent,
    UserOutlined,
    MenuOutlined,
    LogoutOutlined,
  },
  setup() {
    const route = useRoute();
    const router = useRouter();

    // userData used to come from a getUserNameByPassword() call whose
    // password argument was injected server-side via a GAS scriptlet
    // ("<?!= userInputPassword ?>"). login() already returns userName/
    // userRole, so the auth store has everything the sidebar needs without
    // an extra round trip.
    const userData = computed(() => ({
      userName: auth.userName,
      userRole: auth.userRole,
    }));

    const collapsed = ref<boolean>(false);
    const isMobile = ref<boolean>(false);

    // 檢測螢幕尺寸
    const checkScreenSize = () => {
      isMobile.value = window.innerWidth <= 768;
      if (isMobile.value) {
        collapsed.value = true; // 手機版預設收起側邊欄
      } else {
        collapsed.value = false; // 桌面版預設展開側邊欄
      }
    };

    // 切換側邊欄
    const toggleSider = () => {
      collapsed.value = !collapsed.value;
    };

    // 處理菜單點擊（手機版點擊後自動收起側邊欄）
    const handleMenuClick = () => {
      if (isMobile.value) {
        collapsed.value = true;
      }
    };

    const handleLogout = () => {
      auth.logout();
      router.push({ name: "login" });
    };

    // 初始化螢幕尺寸檢測
    checkScreenSize();
    window.addEventListener("resize", checkScreenSize);

    onUnmounted(() => {
      window.removeEventListener("resize", checkScreenSize);
    });

    return {
      route,
      userData,
      collapsed,
      isMobile,
      toggleSider,
      handleMenuClick,
      handleLogout,
    };
  },
});
