
import { defineComponent, ref, onMounted } from "vue";
import locale from "ant-design-vue/es/date-picker/locale/zh_TW";
import dayjs from "dayjs";
import type { Dayjs } from "dayjs";
import { TreeProps } from "ant-design-vue";
import "dayjs/locale/zh-tw";
import { fetchProductData } from "@/api/factory-scheduler";
import {
  fetchWorkOrderIds,
  fetchWorkOrderRelatedDataById,
} from "@/api/work-order-data";
import ProductSelector from "@/components/erp-data-selector/ProductSelector.vue";

interface ProductLineDataMapping {
  [key: string]: any;
}

type InputDateRange = [Dayjs, Dayjs];

const productLineDataMapping: ProductLineDataMapping = {
  "101": { color: "rgb(218, 238, 227)", name: "量產" },
  "102": { color: "rgb(126, 250, 144)", name: "精品" },
  "201": { color: "rgb(204, 204, 255)", name: "豆-自動" },
  "202": { color: "rgb(204, 255, 204)", name: "豆-成形" },
  "203": { color: "rgb(255, 204, 255)", name: "濾泡自動" },
  "204": { color: "rgb(255, 255, 204)", name: "濾泡成盒" },
  "205": { color: "rgb(204, 255, 255)", name: "氮氣研磨" },
  "206": { color: "rgb(255, 204, 204)", name: "研磨粉" },
  "207": { color: "rgb(255, 204, 100)", name: "成形袋手工" },
};

export default defineComponent({
  name: "ManufacturerOrderViewer",
  components: {
    ProductSelector,
  },
  props: {},
  setup() {
    dayjs.locale("zh-tw");

    const productData = ref([]);
    const productDataMapping: any = ref({});
    const workOrderTreeArray = ref<Array<any>>([]);
    const userInputBatchNumber = ref(null);
    const userSelectedProductionLine = ref(null);
    const userInputDateRange = ref<InputDateRange>([
      dayjs().subtract(1, "month").startOf("month"),
      dayjs().subtract(1, "month").endOf("month"),
    ]);
    const userInputProduct = ref(null);
    const isLoading = ref(false);
    const lossRateInformation = ref({
      總領用生豆量: 0,
      總產出生豆量: 0,
      總失重率: 0,
      全為熟豆製令: true,
    });
    onMounted(() => {
      isLoading.value = true;
      fetchProductData("成品需求", (data: any): void => {
        productData.value = data.產品;
        isLoading.value = false;

        data.產品.forEach((product: any) => {
          productDataMapping.value[product[0]] = {
            品號: product[0],
            品名: product[1],
            規格: product[2],
          };
        });
        // console.log("data", data);
      });
    });

    // user input method
    const queryTime = ref(0);
    const onSelectProduct = (product: any) => {
      userInputProduct.value = product;
    };
    const queryWorkIdsByFilter = () => {
      isLoading.value = true;

      // clear previous data
      workOrderTreeArray.value = [];

      let userQueryWorkOrderIdsFilter = {
        批號: userInputBatchNumber.value ? userInputBatchNumber.value : null,
        產線: userSelectedProductionLine.value
          ? userSelectedProductionLine.value
          : null,
        日期: [
          userInputDateRange.value[0].format("YYYYMMDD"),
          userInputDateRange.value[1].format("YYYYMMDD"),
        ],
        產品: userInputProduct.value ? userInputProduct.value : null,
      };
      console.log("userQueryWorkOrderIdsFilter", userQueryWorkOrderIdsFilter);
      queryTime.value += 1; // 為了觸發 tree 的 reload，因為 key 一樣不會重新 load data
      fetchWorkOrderIds(
        userQueryWorkOrderIdsFilter,
        (workOrderIdList: any): void => {
          console.log("data", workOrderIdList);
          lossRateInformation.value.總領用生豆量 = 0;
          lossRateInformation.value.總產出生豆量 = 0;
          lossRateInformation.value.總失重率 = 0;
          lossRateInformation.value.全為熟豆製令 = true;
          // update new data
          workOrderTreeArray.value = workOrderIdList.map((workOrderId: any) => {
            let productString =
              productDataMapping.value[workOrderId[2]].品名 +
              " / " +
              productDataMapping.value[workOrderId[2]].規格 +
              " ( " +
              workOrderId[2] +
              " )";

            let workOrderIdString = workOrderId[0] + "-" + workOrderId[1];
            const rawBeanAmount = parseFloat(workOrderId[6]);
            const roastedBeanAmount = parseFloat(workOrderId[7]);
            lossRateInformation.value.總領用生豆量 += isNaN(rawBeanAmount)
              ? 0
              : rawBeanAmount;
            lossRateInformation.value.總產出生豆量 += isNaN(roastedBeanAmount)
              ? 0
              : roastedBeanAmount;
            if (!workOrderId[2].startsWith("2")) {
              lossRateInformation.value.全為熟豆製令 = false;
            }
            return {
              title: workOrderIdString + " | " + productString,
              key: workOrderIdString + "|" + queryTime.value,
              class: "work-order-node",
              品名: productDataMapping.value[workOrderId[2]].品名,
              規格: productDataMapping.value[workOrderId[2]].規格,
              品號: workOrderId[2],
              製令單號: workOrderIdString,
              預計產量: workOrderId[3],
              已領套數: workOrderId[4],
              已生產量: workOrderId[5],
              生豆領用: rawBeanAmount,
              熟豆產量: roastedBeanAmount,
              成品平均成本: workOrderId[8] / workOrderId[5],
            };
          });
          lossRateInformation.value.總失重率 =
            1 -
            lossRateInformation.value.總產出生豆量 /
              lossRateInformation.value.總領用生豆量;
          workOrderTreeArray.value = [...workOrderTreeArray.value];
          isLoading.value = false;
        }
      );
    };

    // tree load data
    const onLoadData: TreeProps["loadData"] = (treeNode: any) => {
      return new Promise<void>((resolve) => {
        if (treeNode.dataRef.children) {
          // already loaded
          resolve();
          return;
        }

        // get tree node data
        console.log("treeNode", treeNode);
        if (treeNode.dataRef.class == "work-order-node") {
          // 展開了製令節點
          fetchWorkOrderRelatedDataById(
            treeNode.key.split("|")[0],
            (data: any): void => {
              console.log("data", data);
              let childrenData: any = [];

              for (let i = 0; i < data.length; i++) {
                let cuData = data[i];

                let isLeaf = false;
                let rowType = "未知";
                let sheetId = "";
                let materialName = "";
                let changeReason = "";
                let changeVersion = "";
                let sheetDate = "";
                let batchNum = "";
                let totalNeed = "";
                let totalReceived = "";
                let recivedMaterialAmount = "";
                let recivedMaterialBatchNum = "";
                let recivedMaterialUnitPrice = "";
                let inoutStockNum = "";

                switch (cuData[8]) {
                  case "單身":
                    rowType = "材料";
                    materialName =
                      productDataMapping.value[cuData[0]].品名 +
                      " / " +
                      productDataMapping.value[cuData[0]].規格;
                    totalNeed = parseFloat(cuData[1]).toFixed(1).toString();
                    totalReceived = parseFloat(cuData[2]).toFixed(1).toString();
                    isLeaf = true;
                    break;
                  case "變更":
                    rowType = "變更";
                    changeVersion = parseFloat(cuData[0])
                      .toString()
                      .padStart(4, "0");
                    changeReason = cuData[2];
                    sheetDate = cuData[1];
                    isLeaf = true;
                    break;
                  case "領退料":
                    rowType = parseInt(cuData[2]) <= 55 ? "領料" : "退料";
                    sheetId = cuData[0];
                    recivedMaterialAmount = parseFloat(cuData[4])
                      .toFixed(1)
                      .toString();
                    materialName =
                      productDataMapping.value[cuData[3]].品名 +
                      " / " +
                      productDataMapping.value[cuData[3]].規格;
                    recivedMaterialBatchNum = cuData[5];
                    recivedMaterialUnitPrice = cuData[6];
                    sheetDate = cuData[1];
                    isLeaf = true;
                    break;
                  case "入出庫":
                    rowType = parseInt(cuData[2]) == 1 ? "入庫" : "出庫";
                    sheetId = cuData[0];
                    materialName =
                      productDataMapping.value[cuData[3]].品名 +
                      " / " +
                      productDataMapping.value[cuData[3]].規格;
                    sheetDate = cuData[1];
                    batchNum = cuData[5];
                    inoutStockNum = parseFloat(cuData[4]).toFixed(1).toString();
                    isLeaf = true;
                    break;
                }
                childrenData.push({
                  title: "",
                  key: `${treeNode.eventKey}-${i}`,
                  rowType: rowType,
                  sheetId: sheetId,
                  materialName: materialName,
                  changeReason: changeReason,
                  changeVersion: changeVersion,
                  sheetDate: sheetDate,
                  batchNum: batchNum,
                  totalNeed: totalNeed,
                  totalReceived: totalReceived,
                  recivedMaterialAmount: recivedMaterialAmount,
                  recivedMaterialBatchNum: recivedMaterialBatchNum,
                  recivedMaterialUnitPrice: recivedMaterialUnitPrice,
                  inoutStockNum: inoutStockNum,
                  isLeaf: isLeaf,
                  // 從父節點（製令）獲取數據用於損耗率計算
                  workOrderProductId: treeNode.dataRef.品號,
                  workOrderPlannedQuantity: parseFloat(
                    treeNode.dataRef.預計產量
                  ),
                  workOrderProducedQuantity: parseFloat(
                    treeNode.dataRef.已生產量
                  ),
                });
              }
              // treeNode.dataRef.children = [
              //   {
              //     title: "製令相關資料位置",
              //     key: `${treeNode.eventKey}-0`,
              //     isLeaf: true,
              //   },
              //   { title: "製令變更單", key: `${treeNode.eventKey}-1` },
              //   { title: "領/退料單", key: `${treeNode.eventKey}-2` },
              // ];
              // this line is important to trigger the tree UI to update
              treeNode.dataRef.children = childrenData;
              workOrderTreeArray.value = [...workOrderTreeArray.value];
              resolve();
            }
          );
          // work order node
        } else {
          // other node
          setTimeout(() => {
            resolve();
          }, 1000);
        }
        // setTimeout(() => {
        //   treeNode.dataRef.children = [
        //     {
        //       title: "製令相關資料位置",
        //       key: `${treeNode.eventKey}-0`,
        //       isLeaf: true,
        //     },
        //     { title: "製令變更單", key: `${treeNode.eventKey}-1` },
        //     { title: "領/退料單", key: `${treeNode.eventKey}-2` },
        //   ];
        //   // this line is important to trigger the tree UI to update
        //   workOrderTreeArray.value = [...workOrderTreeArray.value];
        //   resolve();
        // }, 1000);
      });
    };

    // 計算材料損耗率的方法
    const calculateMaterialLossRate = (
      totalReceived: number,
      totalNeed: number,
      plannedQuantity: number,
      producedQuantity: number
    ): number => {
      if (totalReceived === 0) return 0;
      const adjustedNeed = (totalNeed / plannedQuantity) * producedQuantity;
      return ((totalReceived - adjustedNeed) / totalReceived) * 100;
    };

    return {
      // lib
      dayjs,
      locale,
      // data
      productData,
      productLineDataMapping,
      workOrderTreeArray,
      // status
      isLoading,
      // user input
      userInputBatchNumber,
      userSelectedProductionLine,
      userInputDateRange,
      // method
      onSelectProduct,
      queryWorkIdsByFilter,
      onLoadData,
      calculateMaterialLossRate,
      // status
      lossRateInformation,
    };
  },
});
