import { reactive } from "vue";

const STORAGE_TOKEN_KEY = "cors_auth_token";
const STORAGE_USER_KEY = "cors_auth_user";

interface StoredUser {
  userUnifiedID: string;
  userName: string;
  userRole: string[];
}

function loadStoredUser(): StoredUser | null {
  const raw = localStorage.getItem(STORAGE_USER_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

const state = reactive({
  token: localStorage.getItem(STORAGE_TOKEN_KEY) || "",
  user: loadStoredUser() as StoredUser | null,
});

function setSession(
  token: string,
  userUnifiedID: string,
  userName: string,
  userRole: string[]
) {
  state.token = token;
  state.user = { userUnifiedID, userName, userRole };
  localStorage.setItem(STORAGE_TOKEN_KEY, token);
  localStorage.setItem(STORAGE_USER_KEY, JSON.stringify(state.user));
}

function logout() {
  state.token = "";
  state.user = null;
  localStorage.removeItem(STORAGE_TOKEN_KEY);
  localStorage.removeItem(STORAGE_USER_KEY);
}

export default {
  get token() {
    return state.token;
  },
  get userUnifiedID() {
    return state.user ? state.user.userUnifiedID : "";
  },
  get userName() {
    return state.user ? state.user.userName : "";
  },
  get userRole() {
    return state.user ? state.user.userRole : [];
  },
  get isLoggedIn() {
    return !!state.token && !!state.user;
  },
  get isAdmin() {
    return !!state.user && state.user.userRole.includes("admin");
  },
  setSession,
  logout,
};
