import { callApi } from "./client";

export function fetchMachineHistoryById(machineId: string) {
  return callApi<any[]>("queryDBRepairHistoryByMachineID", { machineId });
}

export function fetchMachineInfoById(machineId: string) {
  return callApi<any>("queryDBInformationByMachineID", { machineId });
}

export function fetchMachineAIConclude(machineId: string) {
  return callApi<any>("getMachineAIConcludeFromJson", { machineId });
}
